-- Generated: 2026-03-04T03:23:47.303Z

-- Create Schema
CREATE SCHEMA IF NOT EXISTS grxbooks;
GRANT USAGE ON SCHEMA grxbooks TO authenticated;
GRANT USAGE ON SCHEMA grxbooks TO anon;
GRANT ALL ON SCHEMA grxbooks TO service_role;

-- Set search path
SET search_path TO grxbooks, public;

