-- 1. Create role enum
CREATE TYPE public.app_role AS ENUM ('admin', 'hr', 'manager', 'employee');

-- 2. Create user_roles table
CREATE TABLE grxbooks.user_roles (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
  role app_role NOT NULL,
  created_at timestamp with time zone DEFAULT now() NOT NULL,
  UNIQUE (user_id, role)
);

-- Enable RLS
ALTER TABLE grxbooks.user_roles ENABLE ROW LEVEL SECURITY;

-- 3. Create security definer function to check roles (prevents infinite recursion)
CREATE OR REPLACE FUNCTION grxbooks.has_role(_user_id uuid, _role app_role)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = grxbooks
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM grxbooks.user_roles
    WHERE user_id = _user_id
      AND role = _role
  )
$$;

-- Helper function to check if user is admin or HR
CREATE OR REPLACE FUNCTION grxbooks.is_admin_or_hr(_user_id uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = grxbooks
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM grxbooks.user_roles
    WHERE user_id = _user_id
      AND role IN ('admin', 'hr')
  )
$$;

-- 4. Add employee management columns to profiles
ALTER TABLE grxbooks.profiles 
  ADD COLUMN IF NOT EXISTS email text,
  ADD COLUMN IF NOT EXISTS status text DEFAULT 'active' CHECK (status IN ('active', 'on_leave', 'inactive')),
  ADD COLUMN IF NOT EXISTS join_date date DEFAULT CURRENT_DATE,
  ADD COLUMN IF NOT EXISTS phone text;

-- 5. RLS policies for user_roles (only admins can manage roles)
CREATE POLICY "Users can view their own roles"
  ON grxbooks.user_roles FOR SELECT
  USING (auth.uid() = user_id);

CREATE POLICY "Admins can view all roles"
  ON grxbooks.user_roles FOR SELECT
  USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can insert roles"
  ON grxbooks.user_roles FOR INSERT
  WITH CHECK (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can update roles"
  ON grxbooks.user_roles FOR UPDATE
  USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can delete roles"
  ON grxbooks.user_roles FOR DELETE
  USING (public.has_role(auth.uid(), 'admin'));

-- 6. Update profiles RLS to allow admins/HR to view all employees
CREATE POLICY "Admins and HR can view all profiles"
  ON grxbooks.profiles FOR SELECT
  USING (public.is_admin_or_hr(auth.uid()));

CREATE POLICY "Admins and HR can update all profiles"
  ON grxbooks.profiles FOR UPDATE
  USING (public.is_admin_or_hr(auth.uid()));

CREATE POLICY "Admins and HR can insert profiles"
  ON grxbooks.profiles FOR INSERT
  WITH CHECK (public.is_admin_or_hr(auth.uid()));

CREATE POLICY "Admins and HR can delete profiles"
  ON grxbooks.profiles FOR DELETE
  USING (public.is_admin_or_hr(auth.uid()));

-- 7. Create index for better performance
CREATE INDEX idx_user_roles_user_id ON grxbooks.user_roles(user_id);
CREATE INDEX idx_profiles_status ON grxbooks.profiles(status);
CREATE INDEX idx_profiles_department ON grxbooks.profiles(department);

