-- Migration: 20260216124600_soft_delete.sql
-- ================================================================================
-- Fix CRITICAL Issue #6: Implement soft delete for financial tables
-- This migration adds deleted_at column and updated delete behavior

-- Add deleted_at column to all financial tables
ALTER TABLE financial_records ADD COLUMN deleted_at TIMESTAMP WITH TIME ZONE DEFAULT NULL;
ALTER TABLE invoices ADD COLUMN deleted_at TIMESTAMP WITH TIME ZONE DEFAULT NULL;
ALTER TABLE invoice_items ADD COLUMN deleted_at TIMESTAMP WITH TIME ZONE DEFAULT NULL;
ALTER TABLE payroll_records ADD COLUMN deleted_at TIMESTAMP WITH TIME ZONE DEFAULT NULL;
ALTER TABLE bank_transactions ADD COLUMN deleted_at TIMESTAMP WITH TIME ZONE DEFAULT NULL;
ALTER TABLE chart_of_accounts ADD COLUMN deleted_at TIMESTAMP WITH TIME ZONE DEFAULT NULL;
ALTER TABLE scheduled_payments ADD COLUMN deleted_at TIMESTAMP WITH TIME ZONE DEFAULT NULL;

-- Add indexes for soft delete queries (to filter out deleted records efficiently)
CREATE INDEX idx_financial_records_deleted ON financial_records(deleted_at) WHERE deleted_at IS NULL;
CREATE INDEX idx_invoices_deleted ON invoices(deleted_at) WHERE deleted_at IS NULL;
CREATE INDEX idx_payroll_records_deleted ON payroll_records(deleted_at) WHERE deleted_at IS NULL;
CREATE INDEX idx_bank_transactions_deleted ON bank_transactions(deleted_at) WHERE deleted_at IS NULL;
CREATE INDEX idx_chart_of_accounts_deleted ON chart_of_accounts(deleted_at) WHERE deleted_at IS NULL;

-- Function to soft delete records
CREATE OR REPLACE FUNCTION soft_delete_record()
RETURNS TRIGGER AS $$
BEGIN
  -- Instead of deleting, mark as deleted
  EXECUTE format('UPDATE ONLY %I SET deleted_at = NOW() WHERE id = $1', TG_TABLE_NAME)
  USING OLD.id;
  
  -- Prevent actual deletion
  RETURN NULL;
END;
$$ LANGUAGE plpgsql;

-- Note: We're NOT applying the trigger yet to maintain backward compatibility
-- Instead, we'll update the application code to:
-- 1. Use UPDATE SET deleted_at = NOW() instead of DELETE
-- 2. Add WHERE deleted_at IS NULL to all SELECT queries

-- Function to permanently delete old soft-deleted records (for GDPR/cleanup)
CREATE OR REPLACE FUNCTION permanently_delete_old_records(
  p_table_name TEXT,
  p_days_old INTEGER DEFAULT 2555 -- 7 years default (financial record retention)
) RETURNS INTEGER AS $$
DECLARE
  v_deleted_count INTEGER;
  v_cutoff_date TIMESTAMP WITH TIME ZONE;
BEGIN
  -- Only admins can permanently delete
  IF NOT is_admin_or_hr(auth.uid()) THEN
    RAISE EXCEPTION 'Only administrators can permanently delete records';
  END IF;
  
  v_cutoff_date := NOW() - (p_days_old || ' days')::INTERVAL;
  
  -- Execute dynamic SQL based on table name
  EXECUTE format('
    DELETE FROM %I
    WHERE deleted_at IS NOT NULL
      AND deleted_at < $1
  ', p_table_name)
  USING v_cutoff_date;
  
  GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
  
  RETURN v_deleted_count;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Function to restore soft-deleted records (admin only)
CREATE OR REPLACE FUNCTION restore_deleted_record(
  p_table_name TEXT,
  p_record_id UUID
) RETURNS BOOLEAN AS $$
BEGIN
  -- Only admins can restore
  IF NOT is_admin_or_hr(auth.uid()) THEN
    RAISE EXCEPTION 'Only administrators can restore deleted records';
  END IF;
  
  EXECUTE format('
    UPDATE %I
    SET deleted_at = NULL
    WHERE id = $1
      AND deleted_at IS NOT NULL
  ', p_table_name)
  USING p_record_id;
  
  RETURN FOUND;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Update RLS policies to exclude soft-deleted records
-- Financial Records
DROP POLICY IF EXISTS "Users can view their own financial records" ON financial_records;
CREATE POLICY "Users can view their own non-deleted financial records"
ON financial_records FOR SELECT
USING (auth.uid() = user_id AND deleted_at IS NULL);

-- Invoices
DROP POLICY IF EXISTS "Users can view own invoices" ON invoices;
CREATE POLICY "Users can view own non-deleted invoices"
ON invoices FOR SELECT
USING (auth.uid() = user_id AND deleted_at IS NULL);

-- Payroll
DROP POLICY IF EXISTS "Users can view own payroll" ON payroll_records;
CREATE POLICY "Users can view own non-deleted payroll"
ON payroll_records FOR SELECT
USING (auth.uid() = user_id AND deleted_at IS NULL);

-- Bank Transactions
DROP POLICY IF EXISTS "Users can view own transactions" ON bank_transactions;
CREATE POLICY "Users can view own non-deleted transactions"
ON bank_transactions FOR SELECT
USING (auth.uid() = user_id AND deleted_at IS NULL);

-- Chart of Accounts
DROP POLICY IF EXISTS "Users can view own accounts" ON chart_of_accounts;
CREATE POLICY "Users can view own non-deleted accounts"
ON chart_of_accounts FOR SELECT
USING (auth.uid() = user_id AND deleted_at IS NULL);

-- Admin policy to view soft-deleted records
CREATE POLICY "Admins can view all records including deleted"
ON financial_records FOR SELECT
USING (is_admin_or_hr(auth.uid()));

CREATE POLICY "Admins can view all invoices including deleted"
ON invoices FOR SELECT
USING (is_admin_or_hr(auth.uid()));

CREATE POLICY "Admins can view all payroll including deleted"
ON payroll_records FOR SELECT
USING (is_admin_or_hr(auth.uid()));

-- Helper view for audit purposes (admin only)
CREATE OR REPLACE VIEW deleted_financial_records AS
SELECT 
  'financial_records' as table_name,
  id,
  user_id,
  deleted_at,
  created_at,
  amount,
  description
FROM financial_records
WHERE deleted_at IS NOT NULL
UNION ALL
SELECT 
  'invoices' as table_name,
  id,
  user_id,
  deleted_at,
  created_at,
  amount,
  'Invoice ' || invoice_number as description
FROM invoices
WHERE deleted_at IS NOT NULL
UNION ALL
SELECT 
  'payroll_records' as table_name,
  id,
  user_id,
  deleted_at,
  created_at,
  net_pay as amount,
  'Payroll ' || pay_period as description
FROM payroll_records
WHERE deleted_at IS NOT NULL;

-- Grant permissions
GRANT EXECUTE ON FUNCTION permanently_delete_old_records TO authenticated;
GRANT EXECUTE ON FUNCTION restore_deleted_record TO authenticated;
GRANT SELECT ON deleted_financial_records TO authenticated;

-- Add comments
COMMENT ON COLUMN financial_records.deleted_at IS 'Soft delete timestamp. NULL = active record. Addresses CRITICAL Issue #6 from system audit.';
COMMENT ON COLUMN invoices.deleted_at IS 'Soft delete timestamp. NULL = active record. Addresses CRITICAL Issue #6 from system audit.';
COMMENT ON COLUMN payroll_records.deleted_at IS 'Soft delete timestamp. NULL = active record. Addresses CRITICAL Issue #6 from system audit.';
COMMENT ON FUNCTION permanently_delete_old_records IS 'Permanently deletes soft-deleted records older than specified days (default 7 years). Admin only.';
COMMENT ON FUNCTION restore_deleted_record IS 'Restores a soft-deleted record. Admin only.';
COMMENT ON VIEW deleted_financial_records IS 'Audit view of all soft-deleted financial records. Admin only.';


-- Migration: 20260217000000_dev_tools_rbac.sql
-- ================================================================================
-- =====================================================
-- DEV TOOLS RBAC TABLES
-- =====================================================
-- This migration adds the necessary tables for dev tools
-- to function without the Express backend.
-- It creates a comprehensive RBAC system with:
-- - roles (with priorities and metadata)
-- - permissions (granular permission definitions)
-- - role_permissions (many-to-many junction table)

-- 1. Create roles table
CREATE TABLE IF NOT EXISTS grxbooks.roles (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL UNIQUE,
  description text,
  priority integer NOT NULL DEFAULT 0,
  is_system_role boolean DEFAULT true,
  is_active boolean DEFAULT true,
  created_at timestamp with time zone DEFAULT now() NOT NULL,
  updated_at timestamp with time zone DEFAULT now() NOT NULL
);

-- 2. Create permissions table
CREATE TABLE IF NOT EXISTS grxbooks.permissions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  module text NOT NULL,
  resource text NOT NULL,
  action text NOT NULL,
  permission_string text NOT NULL UNIQUE,
  description text,
  is_active boolean DEFAULT true,
  created_at timestamp with time zone DEFAULT now() NOT NULL,
  updated_at timestamp with time zone DEFAULT now() NOT NULL,
  UNIQUE (module, resource, action)
);

-- 3. Create role_permissions junction table
CREATE TABLE IF NOT EXISTS grxbooks.role_permissions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  role_id uuid REFERENCES public.roles(id) ON DELETE CASCADE NOT NULL,
  permission_id uuid REFERENCES public.permissions(id) ON DELETE CASCADE NOT NULL,
  created_at timestamp with time zone DEFAULT now() NOT NULL,
  UNIQUE (role_id, permission_id)
);

-- Enable RLS
ALTER TABLE grxbooks.roles ENABLE ROW LEVEL SECURITY;
ALTER TABLE grxbooks.permissions ENABLE ROW LEVEL SECURITY;
ALTER TABLE grxbooks.role_permissions ENABLE ROW LEVEL SECURITY;

-- RLS Policies: Allow anyone to read (needed for dev tools)
-- In production, dev tools won't be accessible anyway
CREATE POLICY "Allow read access to roles"
  ON grxbooks.roles FOR SELECT
  USING (true);

CREATE POLICY "Allow read access to permissions"
  ON grxbooks.permissions FOR SELECT
  USING (true);

CREATE POLICY "Allow read access to role_permissions"
  ON grxbooks.role_permissions FOR SELECT
  USING (true);

-- Only admins can modify
CREATE POLICY "Admins can insert roles"
  ON grxbooks.roles FOR INSERT
  WITH CHECK (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can update roles"
  ON grxbooks.roles FOR UPDATE
  USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can delete roles"
  ON grxbooks.roles FOR DELETE
  USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can insert permissions"
  ON grxbooks.permissions FOR INSERT
  WITH CHECK (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can update permissions"
  ON grxbooks.permissions FOR UPDATE
  USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can delete permissions"
  ON grxbooks.permissions FOR DELETE
  USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can insert role_permissions"
  ON grxbooks.role_permissions FOR INSERT
  WITH CHECK (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can update role_permissions"
  ON grxbooks.role_permissions FOR UPDATE
  USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can delete role_permissions"
  ON grxbooks.role_permissions FOR DELETE
  USING (public.has_role(auth.uid(), 'admin'));

-- Create indexes for better performance
CREATE INDEX IF NOT EXISTS idx_roles_name ON grxbooks.roles(name);
CREATE INDEX IF NOT EXISTS idx_roles_priority ON grxbooks.roles(priority DESC);
CREATE INDEX IF NOT EXISTS idx_permissions_module ON grxbooks.permissions(module);
CREATE INDEX IF NOT EXISTS idx_permissions_permission_string ON grxbooks.permissions(permission_string);
CREATE INDEX IF NOT EXISTS idx_role_permissions_role_id ON grxbooks.role_permissions(role_id);
CREATE INDEX IF NOT EXISTS idx_role_permissions_permission_id ON grxbooks.role_permissions(permission_id);

-- Create function to update updated_at timestamp
CREATE OR REPLACE FUNCTION grxbooks.update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create triggers for updated_at
CREATE TRIGGER update_roles_updated_at
  BEFORE UPDATE ON grxbooks.roles
  FOR EACH ROW
  EXECUTE FUNCTION grxbooks.update_updated_at_column();

CREATE TRIGGER update_permissions_updated_at
  BEFORE UPDATE ON grxbooks.permissions
  FOR EACH ROW
  EXECUTE FUNCTION grxbooks.update_updated_at_column();

-- Seed initial roles
INSERT INTO grxbooks.roles (name, description, priority, is_system_role) VALUES
  ('SuperAdmin', 'Full system access with all permissions', 100, true),
  ('Admin', 'Administrative access to most features', 90, true),
  ('Moderator', 'Content moderation capabilities', 50, true),
  ('Author', 'Can create and manage own content', 40, true),
  ('Reader', 'Basic read access', 10, true)
ON CONFLICT (name) DO NOTHING;

-- Seed initial permissions
INSERT INTO grxbooks.permissions (module, resource, action, permission_string, description) VALUES
  -- Books module
  ('books', 'book', 'create', 'books.book.create', 'Create new books'),
  ('books', 'book', 'read', 'books.book.read', 'Read books'),
  ('books', 'book', 'update', 'books.book.update', 'Update existing books'),
  ('books', 'book', 'delete', 'books.book.delete', 'Delete books'),
  ('books', 'book', 'publish', 'books.book.publish', 'Publish books'),
  
  -- Reviews module
  ('reviews', 'review', 'create', 'reviews.review.create', 'Create reviews'),
  ('reviews', 'review', 'read', 'reviews.review.read', 'Read reviews'),
  ('reviews', 'review', 'update', 'reviews.review.update', 'Update reviews'),
  ('reviews', 'review', 'delete', 'reviews.review.delete', 'Delete reviews'),
  ('reviews', 'review', 'moderate', 'reviews.review.moderate', 'Moderate reviews'),
  
  -- Users module
  ('users', 'user', 'create', 'users.user.create', 'Create users'),
  ('users', 'user', 'read', 'users.user.read', 'Read user information'),
  ('users', 'user', 'update', 'users.user.update', 'Update user information'),
  ('users', 'user', 'delete', 'users.user.delete', 'Delete users'),
  
  -- Security module
  ('security', 'role', 'manage', 'security.role.manage', 'Manage roles and permissions'),
  ('security', 'permission', 'manage', 'security.permission.manage', 'Manage permissions'),
  
  -- Wildcard permission (SuperAdmin only)
  ('*', '*', '*', '*', 'Full system access')
ON CONFLICT (permission_string) DO NOTHING;

-- Assign permissions to roles
DO $$
DECLARE
  superadmin_id uuid;
  admin_id uuid;
  moderator_id uuid;
  author_id uuid;
  reader_id uuid;
  wildcard_perm_id uuid;
BEGIN
  -- Get role IDs
  SELECT id INTO superadmin_id FROM grxbooks.roles WHERE name = 'SuperAdmin';
  SELECT id INTO admin_id FROM grxbooks.roles WHERE name = 'Admin';
  SELECT id INTO moderator_id FROM grxbooks.roles WHERE name = 'Moderator';
  SELECT id INTO author_id FROM grxbooks.roles WHERE name = 'Author';
  SELECT id INTO reader_id FROM grxbooks.roles WHERE name = 'Reader';
  
  -- Get wildcard permission ID
  SELECT id INTO wildcard_perm_id FROM grxbooks.permissions WHERE permission_string = '*';
  
  -- SuperAdmin gets wildcard permission
  INSERT INTO grxbooks.role_permissions (role_id, permission_id)
  SELECT superadmin_id, wildcard_perm_id
  WHERE superadmin_id IS NOT NULL AND wildcard_perm_id IS NOT NULL
  ON CONFLICT DO NOTHING;
  
  -- Admin gets all permissions except wildcard
  INSERT INTO grxbooks.role_permissions (role_id, permission_id)
  SELECT admin_id, id
  FROM grxbooks.permissions
  WHERE permission_string != '*' AND admin_id IS NOT NULL
  ON CONFLICT DO NOTHING;
  
  -- Moderator gets read and moderate permissions
  INSERT INTO grxbooks.role_permissions (role_id, permission_id)
  SELECT moderator_id, id
  FROM grxbooks.permissions
  WHERE permission_string IN (
    'books.book.read',
    'reviews.review.read',
    'reviews.review.moderate',
    'reviews.review.delete',
    'users.user.read'
  ) AND moderator_id IS NOT NULL
  ON CONFLICT DO NOTHING;
  
  -- Author gets create/read/update for books and reviews
  INSERT INTO grxbooks.role_permissions (role_id, permission_id)
  SELECT author_id, id
  FROM grxbooks.permissions
  WHERE permission_string IN (
    'books.book.create',
    'books.book.read',
    'books.book.update',
    'reviews.review.create',
    'reviews.review.read',
    'reviews.review.update'
  ) AND author_id IS NOT NULL
  ON CONFLICT DO NOTHING;
  
  -- Reader gets only read permissions
  INSERT INTO grxbooks.role_permissions (role_id, permission_id)
  SELECT reader_id, id
  FROM grxbooks.permissions
  WHERE permission_string IN (
    'books.book.read',
    'reviews.review.read'
  ) AND reader_id IS NOT NULL
  ON CONFLICT DO NOTHING;
END $$;

-- Create RPC function to update role permissions
CREATE OR REPLACE FUNCTION grxbooks.update_role_permissions(
  role_name text,
  permission_strings text[]
)
RETURNS json
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  target_role_id uuid;
  perm_id uuid;
  perm_string text;
  result json;
BEGIN
  -- Check if user has admin role
  IF NOT public.has_role(auth.uid(), 'admin') THEN
    RAISE EXCEPTION 'Only admins can update role permissions';
  END IF;
  
  -- Get role ID
  SELECT id INTO target_role_id FROM grxbooks.roles WHERE name = role_name;
  
  IF target_role_id IS NULL THEN
    RAISE EXCEPTION 'Role % not found', role_name;
  END IF;
  
  -- Delete existing permissions for this role
  DELETE FROM grxbooks.role_permissions WHERE role_id = target_role_id;
  
  -- Insert new permissions
  FOREACH perm_string IN ARRAY permission_strings
  LOOP
    SELECT id INTO perm_id FROM grxbooks.permissions WHERE permission_string = perm_string;
    
    IF perm_id IS NOT NULL THEN
      INSERT INTO grxbooks.role_permissions (role_id, permission_id)
      VALUES (target_role_id, perm_id)
      ON CONFLICT DO NOTHING;
    END IF;
  END LOOP;
  
  -- Return success result
  result := json_build_object(
    'success', true,
    'message', 'Permissions updated successfully',
    'role', role_name,
    'permissions_count', array_length(permission_strings, 1)
  );
  
  RETURN result;
END;
$$;


