-- Migration: 20260218050000_phase1_employee_state_machine.sql
-- ================================================================================
-- ===================================================================
-- PHASE 1: EMPLOYEE LIFECYCLE STATE MACHINE
-- ===================================================================
-- Implements formal state machine for employee lifecycle with
-- transition guards and audit trail
-- ===================================================================

-- 1. Create employee state ENUM
CREATE TYPE public.employee_state AS ENUM (
  'draft',
  'offer_accepted',
  'scheduled',
  'active',
  'on_probation',
  'confirmed',
  'resigned',
  'notice_period',
  'exited',
  'fnf_pending',
  'fnf_completed',
  'archived',
  'anonymized'
);

-- 2. Add state tracking columns to profiles table
ALTER TABLE grxbooks.profiles 
  ADD COLUMN IF NOT EXISTS current_state employee_state DEFAULT 'draft',
  ADD COLUMN IF NOT EXISTS previous_state employee_state,
  ADD COLUMN IF NOT EXISTS state_entered_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  ADD COLUMN IF NOT EXISTS manager_id UUID REFERENCES public.profiles(id),
  ADD COLUMN IF NOT EXISTS employee_id TEXT UNIQUE,
  ADD COLUMN IF NOT EXISTS date_of_birth DATE,
  ADD COLUMN IF NOT EXISTS date_of_joining DATE,
  ADD COLUMN IF NOT EXISTS date_of_exit DATE,
  ADD COLUMN IF NOT EXISTS deleted_at TIMESTAMP WITH TIME ZONE, -- Soft delete
  ADD COLUMN IF NOT EXISTS is_deleted BOOLEAN DEFAULT FALSE;

-- 3. Create state transition history table
CREATE TABLE IF NOT EXISTS grxbooks.state_transition_history (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  profile_id UUID NOT NULL REFERENCES public.profiles(id) ON DELETE CASCADE,
  from_state employee_state,
  to_state employee_state NOT NULL,
  transitioned_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
  transitioned_by UUID REFERENCES auth.users(id),
  reason TEXT,
  metadata JSONB,
  is_valid BOOLEAN DEFAULT TRUE,
  validation_errors TEXT[]
);

-- Enable RLS
ALTER TABLE grxbooks.state_transition_history ENABLE ROW LEVEL SECURITY;

-- Create index for performance
CREATE INDEX idx_state_transition_profile ON grxbooks.state_transition_history(profile_id, transitioned_at DESC);
CREATE INDEX idx_profiles_current_state ON grxbooks.profiles(current_state);
CREATE INDEX idx_profiles_manager ON grxbooks.profiles(manager_id) WHERE manager_id IS NOT NULL;

-- 4. Prevent hard deletion of profiles
CREATE OR REPLACE FUNCTION grxbooks.prevent_profile_deletion()
RETURNS TRIGGER AS $$
BEGIN
  RAISE EXCEPTION 'Direct deletion of employee profiles is not allowed. Use soft delete by setting is_deleted=true';
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER prevent_profile_hard_delete
BEFORE DELETE ON grxbooks.profiles
FOR EACH ROW
EXECUTE FUNCTION grxbooks.prevent_profile_deletion();

-- 5. Create state transition validation function
CREATE OR REPLACE FUNCTION grxbooks.validate_state_transition(
  p_profile_id UUID,
  p_new_state employee_state
)
RETURNS TABLE (
  is_valid BOOLEAN,
  errors TEXT[]
) AS $$
DECLARE
  v_current_state employee_state;
  v_manager_id UUID;
  v_has_direct_reports BOOLEAN;
  v_errors TEXT[] := '{}';
BEGIN
  -- Get current state and manager
  SELECT current_state, manager_id INTO v_current_state, v_manager_id
  FROM grxbooks.profiles
  WHERE id = p_profile_id;

  -- Validate transition rules based on current state
  CASE v_current_state
    WHEN 'draft' THEN
      IF p_new_state NOT IN ('offer_accepted', 'archived') THEN
        v_errors := array_append(v_errors, 'From draft, can only transition to offer_accepted or archived');
      END IF;
    
    WHEN 'offer_accepted' THEN
      IF p_new_state NOT IN ('scheduled', 'archived') THEN
        v_errors := array_append(v_errors, 'From offer_accepted, can only transition to scheduled or archived');
      END IF;
    
    WHEN 'scheduled' THEN
      IF p_new_state NOT IN ('active', 'on_probation', 'archived') THEN
        v_errors := array_append(v_errors, 'From scheduled, can only transition to active, on_probation, or archived');
      END IF;
    
    WHEN 'on_probation' THEN
      IF p_new_state NOT IN ('confirmed', 'exited') THEN
        v_errors := array_append(v_errors, 'From on_probation, can only transition to confirmed or exited');
      END IF;
    
    WHEN 'active', 'confirmed' THEN
      IF p_new_state NOT IN ('resigned', 'exited', 'on_probation') THEN
        v_errors := array_append(v_errors, 'From active/confirmed, can only transition to resigned, exited, or on_probation');
      END IF;
    
    WHEN 'resigned' THEN
      IF p_new_state NOT IN ('notice_period', 'active') THEN
        v_errors := array_append(v_errors, 'From resigned, can only transition to notice_period or back to active (resignation withdrawal)');
      END IF;
    
    WHEN 'notice_period' THEN
      IF p_new_state NOT IN ('exited') THEN
        v_errors := array_append(v_errors, 'From notice_period, can only transition to exited');
      END IF;
    
    WHEN 'exited' THEN
      IF p_new_state NOT IN ('fnf_pending', 'active') THEN
        v_errors := array_append(v_errors, 'From exited, can only transition to fnf_pending or back to active (rehire)');
      END IF;
    
    WHEN 'fnf_pending' THEN
      IF p_new_state NOT IN ('fnf_completed') THEN
        v_errors := array_append(v_errors, 'From fnf_pending, can only transition to fnf_completed');
      END IF;
    
    WHEN 'fnf_completed' THEN
      IF p_new_state NOT IN ('archived') THEN
        v_errors := array_append(v_errors, 'From fnf_completed, can only transition to archived');
      END IF;
    
    WHEN 'archived' THEN
      IF p_new_state NOT IN ('anonymized') THEN
        v_errors := array_append(v_errors, 'From archived, can only transition to anonymized');
      END IF;
    
    WHEN 'anonymized' THEN
      v_errors := array_append(v_errors, 'Cannot transition from anonymized state');
    
    ELSE
      v_errors := array_append(v_errors, 'Unknown current state');
  END CASE;

  -- Check if employee is a manager with unassigned direct reports (for exit transitions)
  IF p_new_state IN ('exited', 'notice_period', 'resigned') THEN
    SELECT EXISTS (
      SELECT 1 FROM grxbooks.profiles 
      WHERE manager_id = p_profile_id 
        AND is_deleted = FALSE
        AND current_state NOT IN ('exited', 'fnf_completed', 'archived', 'anonymized')
    ) INTO v_has_direct_reports;
    
    IF v_has_direct_reports THEN
      v_errors := array_append(v_errors, 'Cannot exit: employee has active direct reports. Please reassign them first');
    END IF;
  END IF;

  -- Return validation result
  RETURN QUERY SELECT 
    array_length(v_errors, 1) IS NULL OR array_length(v_errors, 1) = 0,
    v_errors;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 6. Create state transition function
CREATE OR REPLACE FUNCTION grxbooks.transition_employee_state(
  p_profile_id UUID,
  p_new_state employee_state,
  p_reason TEXT DEFAULT NULL,
  p_metadata JSONB DEFAULT NULL
)
RETURNS TABLE (
  success BOOLEAN,
  message TEXT,
  new_state employee_state,
  errors TEXT[]
) AS $$
DECLARE
  v_current_state employee_state;
  v_is_valid BOOLEAN;
  v_errors TEXT[];
  v_transitioned_by UUID;
BEGIN
  -- Get current user
  v_transitioned_by := auth.uid();
  
  -- Get current state
  SELECT current_state INTO v_current_state
  FROM grxbooks.profiles
  WHERE id = p_profile_id;

  -- Check if profile exists
  IF v_current_state IS NULL THEN
    RETURN QUERY SELECT 
      FALSE,
      'Employee profile not found',
      NULL::employee_state,
      ARRAY['Profile does not exist']::TEXT[];
    RETURN;
  END IF;

  -- Validate transition
  SELECT is_valid, validate_state_transition.errors 
  INTO v_is_valid, v_errors
  FROM grxbooks.validate_state_transition(p_profile_id, p_new_state);

  -- If validation fails, return errors
  IF NOT v_is_valid THEN
    -- Log failed transition attempt
    INSERT INTO grxbooks.state_transition_history (
      profile_id, from_state, to_state, transitioned_by, 
      reason, metadata, is_valid, validation_errors
    ) VALUES (
      p_profile_id, v_current_state, p_new_state, v_transitioned_by,
      p_reason, p_metadata, FALSE, v_errors
    );
    
    RETURN QUERY SELECT 
      FALSE,
      'State transition validation failed',
      v_current_state,
      v_errors;
    RETURN;
  END IF;

  -- Perform the transition
  UPDATE grxbooks.profiles
  SET 
    previous_state = current_state,
    current_state = p_new_state,
    state_entered_at = NOW(),
    updated_at = NOW(),
    -- Set dates based on transition
    date_of_joining = CASE 
      WHEN p_new_state IN ('active', 'on_probation') AND date_of_joining IS NULL 
      THEN CURRENT_DATE 
      ELSE date_of_joining 
    END,
    date_of_exit = CASE 
      WHEN p_new_state = 'exited' AND date_of_exit IS NULL 
      THEN CURRENT_DATE 
      ELSE date_of_exit 
    END
  WHERE id = p_profile_id;

  -- Log successful transition
  INSERT INTO grxbooks.state_transition_history (
    profile_id, from_state, to_state, transitioned_by,
    reason, metadata, is_valid, validation_errors
  ) VALUES (
    p_profile_id, v_current_state, p_new_state, v_transitioned_by,
    p_reason, p_metadata, TRUE, NULL
  );

  RETURN QUERY SELECT 
    TRUE,
    format('Successfully transitioned from %s to %s', v_current_state, p_new_state),
    p_new_state,
    NULL::TEXT[];
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Grant permissions
GRANT EXECUTE ON FUNCTION grxbooks.validate_state_transition TO authenticated;
GRANT EXECUTE ON FUNCTION grxbooks.transition_employee_state TO authenticated;

-- RLS Policies for state_transition_history
CREATE POLICY "Users can view their own state history"
  ON grxbooks.state_transition_history FOR SELECT
  USING (
    profile_id IN (SELECT id FROM grxbooks.profiles WHERE user_id = auth.uid())
  );

CREATE POLICY "Admins and HR can view all state history"
  ON grxbooks.state_transition_history FOR SELECT
  USING (public.is_admin_or_hr(auth.uid()));

CREATE POLICY "Admins and HR can insert state history"
  ON grxbooks.state_transition_history FOR INSERT
  WITH CHECK (public.is_admin_or_hr(auth.uid()));

-- Add comments
COMMENT ON TYPE employee_state IS 'Employee lifecycle states for the HR system state machine';
COMMENT ON TABLE state_transition_history IS 'Audit trail for all employee state transitions with validation results';
COMMENT ON FUNCTION validate_state_transition IS 'Validates whether a state transition is allowed based on business rules';
COMMENT ON FUNCTION transition_employee_state IS 'Performs validated state transition with full audit trail';
COMMENT ON TRIGGER prevent_profile_hard_delete ON grxbooks.profiles IS 'Prevents hard deletion of employee records, enforcing soft delete only';


-- Migration: 20260218050100_phase2_event_bus_system.sql
-- ================================================================================
-- ===================================================================
-- PHASE 2: EVENT BUS SYSTEM
-- ===================================================================
-- Implements event-driven architecture for HR system
-- All state changes publish events, modules subscribe and react
-- Ensures idempotency and ordered processing
-- ===================================================================

-- 1. Create event type ENUM
CREATE TYPE public.hr_event_type AS ENUM (
  'EmployeeCreated',
  'EmployeeActivated',
  'EmployeeStateChanged',
  'ManagerChanged',
  'SalaryChanged',
  'ExitInitiated',
  'ExitFinalized',
  'FnFCalculated',
  'FnFApproved',
  'FnFCompleted',
  'AssetAssigned',
  'AssetRecovered',
  'AssetRecoveryFailed',
  'PayrollProcessed',
  'LeaveApplied',
  'LeaveApproved',
  'AttendanceMarked',
  'RehireInitiated',
  'LoginRevoked',
  'LoginEnabled'
);

-- 2. Create hr_events table
CREATE TABLE IF NOT EXISTS grxbooks.hr_events (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  event_type hr_event_type NOT NULL,
  entity_type TEXT NOT NULL, -- 'profile', 'payroll', 'asset', etc.
  entity_id UUID NOT NULL,
  payload JSONB NOT NULL,
  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
  created_by UUID REFERENCES auth.users(id),
  processed_at TIMESTAMP WITH TIME ZONE,
  processing_status TEXT DEFAULT 'pending' CHECK (processing_status IN ('pending', 'processing', 'completed', 'failed', 'skipped')),
  processing_error TEXT,
  retry_count INTEGER DEFAULT 0,
  idempotency_key TEXT UNIQUE,
  correlation_id UUID, -- For tracking related events
  metadata JSONB
);

-- Create indexes
CREATE INDEX idx_hr_events_entity ON grxbooks.hr_events(entity_type, entity_id);
CREATE INDEX idx_hr_events_status ON grxbooks.hr_events(processing_status, created_at);
CREATE INDEX idx_hr_events_type ON grxbooks.hr_events(event_type, created_at DESC);
CREATE INDEX idx_hr_events_idempotency ON grxbooks.hr_events(idempotency_key) WHERE idempotency_key IS NOT NULL;

-- Enable RLS
ALTER TABLE grxbooks.hr_events ENABLE ROW LEVEL SECURITY;

-- 3. Create event subscribers table
CREATE TABLE IF NOT EXISTS grxbooks.event_subscribers (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  subscriber_name TEXT NOT NULL UNIQUE,
  event_types hr_event_type[] NOT NULL,
  is_active BOOLEAN DEFAULT TRUE,
  handler_function TEXT NOT NULL,
  priority INTEGER DEFAULT 100,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- 4. Create event processing log
CREATE TABLE IF NOT EXISTS grxbooks.event_processing_log (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  event_id UUID NOT NULL REFERENCES public.hr_events(id) ON DELETE CASCADE,
  subscriber_name TEXT NOT NULL,
  started_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  completed_at TIMESTAMP WITH TIME ZONE,
  status TEXT NOT NULL CHECK (status IN ('started', 'completed', 'failed')),
  error_message TEXT,
  result JSONB
);

CREATE INDEX idx_event_processing_log_event ON grxbooks.event_processing_log(event_id);
CREATE INDEX idx_event_processing_log_subscriber ON grxbooks.event_processing_log(subscriber_name, started_at DESC);

-- Enable RLS
ALTER TABLE grxbooks.event_processing_log ENABLE ROW LEVEL SECURITY;

-- 5. Function to publish event (with idempotency)
CREATE OR REPLACE FUNCTION grxbooks.publish_hr_event(
  p_event_type hr_event_type,
  p_entity_type TEXT,
  p_entity_id UUID,
  p_payload JSONB,
  p_idempotency_key TEXT DEFAULT NULL,
  p_correlation_id UUID DEFAULT NULL
)
RETURNS UUID AS $$
DECLARE
  v_event_id UUID;
  v_existing_event_id UUID;
BEGIN
  -- Check for idempotency
  IF p_idempotency_key IS NOT NULL THEN
    SELECT id INTO v_existing_event_id
    FROM grxbooks.hr_events
    WHERE idempotency_key = p_idempotency_key;
    
    IF v_existing_event_id IS NOT NULL THEN
      -- Event already exists, return existing ID
      RETURN v_existing_event_id;
    END IF;
  END IF;

  -- Create new event
  INSERT INTO grxbooks.hr_events (
    event_type,
    entity_type,
    entity_id,
    payload,
    created_by,
    idempotency_key,
    correlation_id
  ) VALUES (
    p_event_type,
    p_entity_type,
    p_entity_id,
    p_payload,
    auth.uid(),
    p_idempotency_key,
    p_correlation_id
  ) RETURNING id INTO v_event_id;

  RETURN v_event_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 6. Function to process events
CREATE OR REPLACE FUNCTION grxbooks.process_pending_events(
  p_batch_size INTEGER DEFAULT 10,
  p_event_type hr_event_type DEFAULT NULL
)
RETURNS TABLE (
  event_id UUID,
  event_type hr_event_type,
  status TEXT,
  error TEXT
) AS $$
DECLARE
  v_event RECORD;
  v_subscriber RECORD;
  v_processing_log_id UUID;
  v_result JSONB;
  v_error TEXT;
BEGIN
  -- Lock and fetch pending events
  FOR v_event IN
    SELECT e.*
    FROM grxbooks.hr_events e
    WHERE e.processing_status = 'pending'
      AND (p_event_type IS NULL OR e.event_type = p_event_type)
    ORDER BY e.created_at ASC
    LIMIT p_batch_size
    FOR UPDATE SKIP LOCKED
  LOOP
    -- Update status to processing
    UPDATE grxbooks.hr_events
    SET processing_status = 'processing'
    WHERE id = v_event.id;

    -- Process event with each subscriber
    FOR v_subscriber IN
      SELECT *
      FROM grxbooks.event_subscribers
      WHERE is_active = TRUE
        AND v_event.event_type = ANY(event_types)
      ORDER BY priority ASC
    LOOP
      BEGIN
        -- Log processing start
        INSERT INTO grxbooks.event_processing_log (event_id, subscriber_name, status)
        VALUES (v_event.id, v_subscriber.subscriber_name, 'started')
        RETURNING id INTO v_processing_log_id;

        -- Execute handler (simplified - in production, use pg_background or external worker)
        -- For now, we'll just log that it needs processing
        v_result := jsonb_build_object(
          'subscriber', v_subscriber.subscriber_name,
          'handler', v_subscriber.handler_function,
          'event_type', v_event.event_type,
          'processed', TRUE
        );

        -- Log completion
        UPDATE grxbooks.event_processing_log
        SET 
          status = 'completed',
          completed_at = NOW(),
          result = v_result
        WHERE id = v_processing_log_id;

      EXCEPTION WHEN OTHERS THEN
        v_error := SQLERRM;
        
        -- Log failure
        UPDATE grxbooks.event_processing_log
        SET 
          status = 'failed',
          completed_at = NOW(),
          error_message = v_error
        WHERE id = v_processing_log_id;

        -- Update event retry count
        UPDATE grxbooks.hr_events
        SET 
          retry_count = retry_count + 1,
          processing_error = v_error
        WHERE id = v_event.id;
      END;
    END LOOP;

    -- Mark event as completed
    UPDATE grxbooks.hr_events
    SET 
      processing_status = 'completed',
      processed_at = NOW()
    WHERE id = v_event.id;

    RETURN QUERY SELECT 
      v_event.id,
      v_event.event_type,
      'completed'::TEXT,
      NULL::TEXT;
  END LOOP;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 7. Trigger function to publish events on state changes
CREATE OR REPLACE FUNCTION grxbooks.publish_employee_state_change_event()
RETURNS TRIGGER AS $$
DECLARE
  v_event_type hr_event_type;
  v_idempotency_key TEXT;
BEGIN
  -- Determine event type based on new state
  CASE NEW.current_state
    WHEN 'active' THEN
      v_event_type := 'EmployeeActivated';
    WHEN 'resigned' THEN
      v_event_type := 'ExitInitiated';
    WHEN 'exited' THEN
      v_event_type := 'ExitFinalized';
    WHEN 'fnf_completed' THEN
      v_event_type := 'FnFCompleted';
    ELSE
      v_event_type := 'EmployeeStateChanged';
  END CASE;

  -- Create idempotency key
  v_idempotency_key := format('state_change_%s_%s_%s', 
    NEW.id, 
    NEW.current_state, 
    extract(epoch from NOW())
  );

  -- Publish event
  PERFORM public.publish_hr_event(
    v_event_type,
    'profile',
    NEW.id,
    jsonb_build_object(
      'profile_id', NEW.id,
      'previous_state', OLD.current_state,
      'new_state', NEW.current_state,
      'employee_id', NEW.employee_id,
      'full_name', NEW.full_name,
      'department', NEW.department,
      'manager_id', NEW.manager_id,
      'date_of_joining', NEW.date_of_joining,
      'date_of_exit', NEW.date_of_exit
    ),
    v_idempotency_key,
    gen_random_uuid() -- correlation_id
  );

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 8. Trigger function for manager changes
CREATE OR REPLACE FUNCTION grxbooks.publish_manager_change_event()
RETURNS TRIGGER AS $$
DECLARE
  v_idempotency_key TEXT;
BEGIN
  IF OLD.manager_id IS DISTINCT FROM NEW.manager_id THEN
    v_idempotency_key := format('manager_change_%s_%s_%s', 
      NEW.id, 
      NEW.manager_id, 
      extract(epoch from NOW())
    );

    PERFORM public.publish_hr_event(
      'ManagerChanged',
      'profile',
      NEW.id,
      jsonb_build_object(
        'profile_id', NEW.id,
        'old_manager_id', OLD.manager_id,
        'new_manager_id', NEW.manager_id,
        'employee_id', NEW.employee_id,
        'full_name', NEW.full_name,
        'department', NEW.department
      ),
      v_idempotency_key,
      gen_random_uuid()
    );
  END IF;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 9. Create triggers on profiles table
CREATE TRIGGER profile_state_change_event
AFTER UPDATE ON grxbooks.profiles
FOR EACH ROW
WHEN (OLD.current_state IS DISTINCT FROM NEW.current_state)
EXECUTE FUNCTION grxbooks.publish_employee_state_change_event();

CREATE TRIGGER profile_manager_change_event
AFTER UPDATE ON grxbooks.profiles
FOR EACH ROW
WHEN (OLD.manager_id IS DISTINCT FROM NEW.manager_id)
EXECUTE FUNCTION grxbooks.publish_manager_change_event();

-- 10. Register default event subscribers
INSERT INTO grxbooks.event_subscribers (subscriber_name, event_types, handler_function, priority) VALUES
  ('payroll_subscriber', ARRAY['EmployeeActivated', 'SalaryChanged', 'ExitFinalized']::hr_event_type[], 'handle_payroll_events', 100),
  ('asset_subscriber', ARRAY['EmployeeActivated', 'ExitInitiated', 'ExitFinalized']::hr_event_type[], 'handle_asset_events', 200),
  ('access_control_subscriber', ARRAY['EmployeeActivated', 'ExitFinalized', 'FnFCompleted']::hr_event_type[], 'handle_access_control_events', 50),
  ('finance_subscriber', ARRAY['PayrollProcessed', 'FnFCompleted', 'AssetAssigned', 'AssetRecovered']::hr_event_type[], 'handle_finance_events', 150),
  ('manager_sync_subscriber', ARRAY['ManagerChanged']::hr_event_type[], 'handle_manager_sync_events', 75)
ON CONFLICT (subscriber_name) DO NOTHING;

-- Grant permissions
GRANT EXECUTE ON FUNCTION grxbooks.publish_hr_event TO authenticated;
GRANT EXECUTE ON FUNCTION grxbooks.process_pending_events TO authenticated;

-- RLS Policies
CREATE POLICY "Admins and HR can view all events"
  ON grxbooks.hr_events FOR SELECT
  USING (public.is_admin_or_hr(auth.uid()));

CREATE POLICY "System can insert events"
  ON grxbooks.hr_events FOR INSERT
  WITH CHECK (true); -- Events can be created by triggers

CREATE POLICY "Admins can view processing log"
  ON grxbooks.event_processing_log FOR SELECT
  USING (public.is_admin_or_hr(auth.uid()));

-- Add comments
COMMENT ON TABLE hr_events IS 'Event bus for HR system - all state changes publish events here';
COMMENT ON TABLE event_subscribers IS 'Registry of event subscribers and their handlers';
COMMENT ON TABLE event_processing_log IS 'Audit trail of event processing by subscribers';
COMMENT ON FUNCTION publish_hr_event IS 'Publishes an event to the event bus with idempotency support';
COMMENT ON FUNCTION process_pending_events IS 'Processes pending events in batch with all registered subscribers';


