-- 2. Function to get config value
CREATE OR REPLACE FUNCTION grxbooks.get_payroll_config(
  p_config_key TEXT,
  p_effective_date DATE DEFAULT CURRENT_DATE
)
RETURNS JSONB AS $$
DECLARE
  v_config JSONB;
BEGIN
  SELECT config_value INTO v_config
  FROM grxbooks.payroll_config
  WHERE config_key = p_config_key
    AND effective_from <= p_effective_date
    AND (effective_to IS NULL OR effective_to >= p_effective_date)
    AND is_active = TRUE
  ORDER BY effective_from DESC
  LIMIT 1;
  
  RETURN v_config;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 3. Function to calculate PF
CREATE OR REPLACE FUNCTION grxbooks.calculate_pf(
  p_basic_salary NUMERIC,
  p_hra NUMERIC DEFAULT 0
)
RETURNS JSONB AS $$
DECLARE
  v_config JSONB;
  v_pf_wage NUMERIC;
  v_employee_pf NUMERIC;
  v_employer_pf NUMERIC;
  v_employer_pension NUMERIC;
  v_employer_admin NUMERIC;
  v_total_employer NUMERIC;
BEGIN
  v_config := public.get_payroll_config('pf_rates');
  
  -- PF wage = Basic + HRA (capped at ceiling)
  v_pf_wage := LEAST(p_basic_salary + p_hra, (v_config->>'wage_ceiling')::NUMERIC);
  
  -- Employee contribution: 12% of PF wage
  v_employee_pf := ROUND(v_pf_wage * (v_config->>'employee_rate')::NUMERIC, 2);
  
  -- Employer contribution: 12% of PF wage (split into pension and PF)
  v_employer_pension := ROUND(
    LEAST(v_pf_wage, (v_config->>'pension_ceiling')::NUMERIC) * 0.0833, 2
  ); -- 8.33% to pension
  v_employer_pf := ROUND(v_pf_wage * (v_config->>'employer_rate')::NUMERIC, 2) - v_employer_pension;
  
  -- Employer admin charges: 1.1%
  v_employer_admin := ROUND(v_pf_wage * (v_config->>'employer_admin_rate')::NUMERIC, 2);
  
  v_total_employer := v_employer_pf + v_employer_pension + v_employer_admin;
  
  RETURN jsonb_build_object(
    'pf_wage', v_pf_wage,
    'employee_contribution', v_employee_pf,
    'employer_contribution', v_total_employer,
    'employer_pf', v_employer_pf,
    'employer_pension', v_employer_pension,
    'employer_admin', v_employer_admin,
    'total_pf', v_employee_pf + v_total_employer
  );
END;
$$ LANGUAGE plpgsql IMMUTABLE;

-- 4. Function to calculate ESI
CREATE OR REPLACE FUNCTION grxbooks.calculate_esi(
  p_gross_salary NUMERIC
)
RETURNS JSONB AS $$
DECLARE
  v_config JSONB;
  v_is_eligible BOOLEAN;
  v_employee_esi NUMERIC := 0;
  v_employer_esi NUMERIC := 0;
BEGIN
  v_config := public.get_payroll_config('esi_rates');
  
  -- ESI is applicable if gross <= 21,000
  v_is_eligible := p_gross_salary <= (v_config->>'wage_ceiling')::NUMERIC;
  
  IF v_is_eligible THEN
    v_employee_esi := ROUND(p_gross_salary * (v_config->>'employee_rate')::NUMERIC, 2);
    v_employer_esi := ROUND(p_gross_salary * (v_config->>'employer_rate')::NUMERIC, 2);
  END IF;
  
  RETURN jsonb_build_object(
    'is_eligible', v_is_eligible,
    'wage_ceiling', (v_config->>'wage_ceiling')::NUMERIC,
    'gross_salary', p_gross_salary,
    'employee_contribution', v_employee_esi,
    'employer_contribution', v_employer_esi,
    'total_esi', v_employee_esi + v_employer_esi
  );
END;
$$ LANGUAGE plpgsql IMMUTABLE;

-- 5. Function to calculate Professional Tax
CREATE OR REPLACE FUNCTION grxbooks.calculate_professional_tax(
  p_gross_salary NUMERIC,
  p_state TEXT DEFAULT 'Maharashtra'
)
RETURNS JSONB AS $$
DECLARE
  v_config JSONB;
  v_slabs JSONB;
  v_slab JSONB;
  v_pt_amount NUMERIC := 0;
BEGIN
  v_config := public.get_payroll_config('professional_tax');
  v_slabs := v_config->p_state;
  
  IF v_slabs IS NULL THEN
    RETURN jsonb_build_object(
      'state', p_state,
      'pt_amount', 0,
      'error', 'PT slabs not configured for state'
    );
  END IF;
  
  -- Find applicable slab
  FOR v_slab IN SELECT * FROM jsonb_array_elements(v_slabs::JSONB)
  LOOP
    IF p_gross_salary >= (v_slab->>'from')::NUMERIC 
       AND p_gross_salary <= (v_slab->>'to')::NUMERIC THEN
      v_pt_amount := (v_slab->>'tax')::NUMERIC;
      EXIT;
    END IF;
  END LOOP;
  
  RETURN jsonb_build_object(
    'state', p_state,
    'gross_salary', p_gross_salary,
    'pt_amount', v_pt_amount
  );
END;
$$ LANGUAGE plpgsql IMMUTABLE;

-- 6. Function to calculate yearly TDS projection
CREATE OR REPLACE FUNCTION grxbooks.calculate_tds_projection(
  p_profile_id UUID,
  p_tax_regime TEXT DEFAULT 'new_regime'
)
RETURNS JSONB AS $$
DECLARE
  v_annual_ctc NUMERIC;
  v_monthly_gross NUMERIC;
  v_config JSONB;
  v_slabs JSONB;
  v_slab JSONB;
  v_taxable_income NUMERIC;
  v_tax NUMERIC := 0;
  v_cess NUMERIC;
  v_total_tax NUMERIC;
  v_monthly_tds NUMERIC;
  v_standard_deduction NUMERIC;
BEGIN
  -- Get current salary
  SELECT annual_ctc, monthly_gross INTO v_annual_ctc, v_monthly_gross
  FROM grxbooks.salary_structures
  WHERE profile_id = p_profile_id
    AND is_current = TRUE
    AND status = 'active'
  LIMIT 1;

  IF v_annual_ctc IS NULL THEN
    RETURN jsonb_build_object('error', 'No active salary structure found');
  END IF;

  -- Get tax config
  IF p_tax_regime = 'old_regime' THEN
    v_config := public.get_payroll_config('tds_slabs_old_regime');
  ELSE
    v_config := public.get_payroll_config('tds_slabs_new_regime');
  END IF;
  
  v_standard_deduction := (v_config->>'standard_deduction')::NUMERIC;
  v_slabs := v_config->'slabs';
  
  -- Calculate taxable income
  v_taxable_income := v_annual_ctc - v_standard_deduction;
  
  -- Calculate tax as per slabs
  FOR v_slab IN SELECT * FROM jsonb_array_elements(v_slabs::JSONB)
  LOOP
    DECLARE
      v_from NUMERIC := (v_slab->>'from')::NUMERIC;
      v_to NUMERIC := (v_slab->>'to')::NUMERIC;
      v_rate NUMERIC := (v_slab->>'rate')::NUMERIC;
      v_slab_income NUMERIC;
    BEGIN
      IF v_taxable_income > v_from THEN
        v_slab_income := LEAST(v_taxable_income, v_to) - v_from;
        v_tax := v_tax + (v_slab_income * v_rate);
      END IF;
    END;
  END LOOP;
  
  -- Add cess (4% on tax)
  v_cess := ROUND(v_tax * (v_config->>'cess')::NUMERIC, 2);
  v_total_tax := ROUND(v_tax + v_cess, 2);
  v_monthly_tds := ROUND(v_total_tax / 12, 2);
  
  RETURN jsonb_build_object(
    'tax_regime', p_tax_regime,
    'annual_ctc', v_annual_ctc,
    'standard_deduction', v_standard_deduction,
    'taxable_income', v_taxable_income,
    'tax_before_cess', ROUND(v_tax, 2),
    'cess', v_cess,
    'total_annual_tax', v_total_tax,
    'monthly_tds', v_monthly_tds
  );
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 7. Master Payroll Processing Function
CREATE OR REPLACE FUNCTION grxbooks.process_payroll_for_employee(
  p_profile_id UUID,
  p_pay_period TEXT, -- Format: YYYY-MM
  p_tax_regime TEXT DEFAULT 'new_regime',
  p_state TEXT DEFAULT 'Maharashtra'
)
RETURNS UUID AS $$
DECLARE
  v_payroll_id UUID;
  v_salary_structure RECORD;
  v_pf_calc JSONB;
  v_esi_calc JSONB;
  v_pt_calc JSONB;
  v_tds_calc JSONB;
  v_basic NUMERIC;
  v_hra NUMERIC;
  v_gross NUMERIC;
  v_pf_deduction NUMERIC;
  v_esi_deduction NUMERIC;
  v_pt_deduction NUMERIC;
  v_tds_deduction NUMERIC;
  v_total_deductions NUMERIC;
  v_net_pay NUMERIC;
  v_idempotency_key TEXT;
BEGIN
  -- Get current salary structure
  SELECT * INTO v_salary_structure
  FROM grxbooks.salary_structures
  WHERE profile_id = p_profile_id
    AND is_current = TRUE
    AND status = 'active'
  LIMIT 1;

  IF v_salary_structure IS NULL THEN
    RAISE EXCEPTION 'No active salary structure found for employee';
  END IF;

  -- Extract salary components
  v_basic := COALESCE((v_salary_structure.structure_json->>'basic')::NUMERIC, v_salary_structure.monthly_gross * 0.4);
  v_hra := COALESCE((v_salary_structure.structure_json->>'hra')::NUMERIC, v_salary_structure.monthly_gross * 0.3);
  v_gross := v_salary_structure.monthly_gross;

  -- Calculate statutory deductions
  v_pf_calc := public.calculate_pf(v_basic, v_hra);
  v_esi_calc := public.calculate_esi(v_gross);
  v_pt_calc := public.calculate_professional_tax(v_gross, p_state);
  v_tds_calc := public.calculate_tds_projection(p_profile_id, p_tax_regime);

  -- Get deduction amounts
  v_pf_deduction := (v_pf_calc->>'employee_contribution')::NUMERIC;
  v_esi_deduction := (v_esi_calc->>'employee_contribution')::NUMERIC;
  v_pt_deduction := (v_pt_calc->>'pt_amount')::NUMERIC;
  v_tds_deduction := (v_tds_calc->>'monthly_tds')::NUMERIC;

  -- Calculate totals
  v_total_deductions := v_pf_deduction + v_esi_deduction + v_pt_deduction + v_tds_deduction;
  v_net_pay := v_gross - v_total_deductions;

  -- Idempotency key
  v_idempotency_key := format('payroll_%s_%s', p_profile_id, p_pay_period);

  -- Insert payroll record
  INSERT INTO grxbooks.payroll_records (
    profile_id,
    pay_period,
    basic_salary,
    hra,
    transport_allowance,
    other_allowances,
    pf_deduction,
    tax_deduction,
    other_deductions,
    net_pay,
    status
  ) VALUES (
    p_profile_id,
    p_pay_period,
    v_basic,
    v_hra,
    COALESCE((v_salary_structure.structure_json->>'transport')::NUMERIC, 0),
    v_gross - v_basic - v_hra,
    v_pf_deduction,
    v_tds_deduction,
    v_esi_deduction + v_pt_deduction,
    v_net_pay,
    'draft'
  )
  ON CONFLICT (profile_id, pay_period)
  DO UPDATE SET
    basic_salary = EXCLUDED.basic_salary,
    hra = EXCLUDED.hra,
    transport_allowance = EXCLUDED.transport_allowance,
    other_allowances = EXCLUDED.other_allowances,
    pf_deduction = EXCLUDED.pf_deduction,
    tax_deduction = EXCLUDED.tax_deduction,
    other_deductions = EXCLUDED.other_deductions,
    net_pay = EXCLUDED.net_pay,
    updated_at = NOW()
  WHERE public.payroll_records.is_locked = FALSE
  RETURNING id INTO v_payroll_id;

  -- Publish event
  PERFORM public.publish_hr_event(
    'PayrollProcessed',
    'payroll_record',
    v_payroll_id,
    jsonb_build_object(
      'profile_id', p_profile_id,
      'pay_period', p_pay_period,
      'gross_salary', v_gross,
      'net_pay', v_net_pay,
      'pf_calc', v_pf_calc,
      'esi_calc', v_esi_calc,
      'pt_calc', v_pt_calc,
      'tds_calc', v_tds_calc
    ),
    v_idempotency_key,
    gen_random_uuid()
  );

  RETURN v_payroll_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Grant permissions
GRANT EXECUTE ON FUNCTION grxbooks.calculate_pf TO authenticated;
GRANT EXECUTE ON FUNCTION grxbooks.calculate_esi TO authenticated;
GRANT EXECUTE ON FUNCTION grxbooks.calculate_professional_tax TO authenticated;
GRANT EXECUTE ON FUNCTION grxbooks.calculate_tds_projection TO authenticated;
GRANT EXECUTE ON FUNCTION grxbooks.process_payroll_for_employee TO authenticated;

-- RLS for payroll_config
CREATE POLICY "Admins can view payroll config"
  ON grxbooks.payroll_config FOR SELECT
  USING (public.has_role(auth.uid(), 'admin'));

CREATE POLICY "Admins can manage payroll config"
  ON grxbooks.payroll_config FOR ALL
  USING (public.has_role(auth.uid(), 'admin'));

-- Add comments
COMMENT ON TABLE payroll_config IS 'Configuration for payroll calculations including PF, ESI, PT, TDS rates';
COMMENT ON FUNCTION calculate_pf IS 'Calculates PF with employee/employer split as per EPF Act';
COMMENT ON FUNCTION calculate_esi IS 'Calculates ESI for eligible employees (gross <= 21k) as per ESI Act';
COMMENT ON FUNCTION calculate_professional_tax IS 'Calculates state-wise professional tax';
COMMENT ON FUNCTION calculate_tds_projection IS 'Projects annual TDS and monthly deduction for old/new regime';
COMMENT ON FUNCTION process_payroll_for_employee IS 'Master payroll processing with all India statutory compliance';


-- Migration: 20260218050500_phase6_manager_sync.sql
-- ================================================================================
-- ===================================================================
-- PHASE 6: TWO-WAY MANAGER SYNC WITH MS GRAPH
-- ===================================================================
-- Implements bidirectional sync between HRMS and MS 365
-- Handles conflicts using source_of_truth flag
-- ===================================================================

-- 1. Create MS Graph sync log table
CREATE TABLE IF NOT EXISTS grxbooks.ms_graph_sync_log (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  sync_type TEXT NOT NULL CHECK (sync_type IN ('manager_update', 'user_sync', 'webhook_received')),
  direction TEXT NOT NULL CHECK (direction IN ('hrms_to_graph', 'graph_to_hrms', 'bidirectional')),
  entity_type TEXT NOT NULL,
  entity_id UUID,
  ms_graph_id TEXT,
  status TEXT NOT NULL CHECK (status IN ('pending', 'in_progress', 'completed', 'failed', 'conflict')),
  payload JSONB,
  response JSONB,
  error_message TEXT,
  conflict_resolution TEXT,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  processed_at TIMESTAMP WITH TIME ZONE,
  retry_count INTEGER DEFAULT 0
);

CREATE INDEX idx_ms_graph_sync_status ON grxbooks.ms_graph_sync_log(status, created_at DESC);
CREATE INDEX idx_ms_graph_sync_entity ON grxbooks.ms_graph_sync_log(entity_type, entity_id);

-- Enable RLS
ALTER TABLE grxbooks.ms_graph_sync_log ENABLE ROW LEVEL SECURITY;

-- 2. Function to sync manager to MS Graph
CREATE OR REPLACE FUNCTION grxbooks.sync_manager_to_msgraph(
  p_profile_id UUID,
  p_new_manager_id UUID,
  p_source_of_truth TEXT DEFAULT 'hrms'
)
RETURNS UUID AS $$
DECLARE
  v_sync_log_id UUID;
  v_employee_email TEXT;
  v_manager_email TEXT;
BEGIN
  -- Get emails
  SELECT p1.email, p2.email 
  INTO v_employee_email, v_manager_email
  FROM grxbooks.profiles p1
  LEFT JOIN public.profiles p2 ON p2.id = p_new_manager_id
  WHERE p1.id = p_profile_id;

  -- Log sync attempt
  INSERT INTO grxbooks.ms_graph_sync_log (
    sync_type,
    direction,
    entity_type,
    entity_id,
    status,
    payload
  ) VALUES (
    'manager_update',
    'hrms_to_graph',
    'profile',
    p_profile_id,
    'pending',
    jsonb_build_object(
      'employee_email', v_employee_email,
      'manager_email', v_manager_email,
      'manager_id', p_new_manager_id,
      'source_of_truth', p_source_of_truth
    )
  ) RETURNING id INTO v_sync_log_id;

  -- TODO: Actual MS Graph API call would go here
  -- For now, mark as completed
  UPDATE grxbooks.ms_graph_sync_log
  SET 
    status = 'completed',
    processed_at = NOW(),
    response = jsonb_build_object('status', 'simulated_success')
  WHERE id = v_sync_log_id;

  RETURN v_sync_log_id;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- 3. Function to handle manager changes with conflict resolution
CREATE OR REPLACE FUNCTION grxbooks.handle_manager_change_with_sync(
  p_profile_id UUID,
  p_new_manager_id UUID,
  p_source TEXT DEFAULT 'hrms', -- 'hrms', 'ms_graph', or 'manual'
  p_force BOOLEAN DEFAULT FALSE
)
RETURNS JSONB AS $$
DECLARE
  v_current_manager_id UUID;
  v_source_of_truth TEXT;
  v_sync_status TEXT;
  v_history_id UUID;
BEGIN
  -- Get current manager and source of truth
  SELECT manager_id INTO v_current_manager_id
  FROM grxbooks.profiles
  WHERE id = p_profile_id;

  -- Check if there's a current manager history record
  SELECT source_of_truth INTO v_source_of_truth
  FROM grxbooks.employee_manager_history
  WHERE profile_id = p_profile_id
    AND is_current = TRUE
  LIMIT 1;

  v_source_of_truth := COALESCE(v_source_of_truth, 'hrms');

  -- Handle conflict: if source of truth differs from update source
  IF v_source_of_truth != p_source AND NOT p_force THEN
    -- Log conflict
    INSERT INTO grxbooks.ms_graph_sync_log (
      sync_type,
      direction,
      entity_type,
      entity_id,
      status,
      payload,
      conflict_resolution
    ) VALUES (
      'manager_update',
      'bidirectional',
      'profile',
      p_profile_id,
      'conflict',
      jsonb_build_object(
        'current_manager', v_current_manager_id,
        'new_manager', p_new_manager_id,
        'source_of_truth', v_source_of_truth,
        'update_source', p_source
      ),
      format('Source of truth is %s, update from %s rejected', v_source_of_truth, p_source)
    );

    RETURN jsonb_build_object(
      'success', FALSE,
      'error', 'Conflict detected',
      'source_of_truth', v_source_of_truth,
      'update_source', p_source,
      'message', 'Use force=true to override source of truth'
    );
  END IF;

  -- Close current manager history
  UPDATE grxbooks.employee_manager_history
  SET 
    is_current = FALSE,
    effective_to = CURRENT_DATE,
    updated_at = NOW()
  WHERE profile_id = p_profile_id
    AND is_current = TRUE;

  -- Create new manager history
  INSERT INTO grxbooks.employee_manager_history (
    profile_id,
    manager_id,
    effective_from,
    source_of_truth,
    sync_status,
    is_current
  ) VALUES (
    p_profile_id,
    p_new_manager_id,
    CURRENT_DATE,
    p_source,
    'synced',
    TRUE
  ) RETURNING id INTO v_history_id;

  -- Update current manager in profiles
  UPDATE grxbooks.profiles
  SET 
    manager_id = p_new_manager_id,
    updated_at = NOW()
  WHERE id = p_profile_id;

  -- Sync to MS Graph if source is HRMS
  IF p_source = 'hrms' THEN
    PERFORM public.sync_manager_to_msgraph(p_profile_id, p_new_manager_id, p_source);
    v_sync_status := 'synced_to_graph';
  ELSE
    v_sync_status := 'received_from_graph';
  END IF;

  RETURN jsonb_build_object(
    'success', TRUE,
    'manager_history_id', v_history_id,
    'previous_manager', v_current_manager_id,
    'new_manager', p_new_manager_id,
    'sync_status', v_sync_status
  );
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- Grant permissions
GRANT EXECUTE ON FUNCTION grxbooks.sync_manager_to_msgraph TO authenticated;
GRANT EXECUTE ON FUNCTION grxbooks.handle_manager_change_with_sync TO authenticated;

-- RLS for sync log
CREATE POLICY "Admins can view sync logs"
  ON grxbooks.ms_graph_sync_log FOR SELECT
  USING (public.is_admin_or_hr(auth.uid()));

CREATE POLICY "System can insert sync logs"
  ON grxbooks.ms_graph_sync_log FOR INSERT
  WITH CHECK (true);

-- Add comments
COMMENT ON TABLE ms_graph_sync_log IS 'Audit trail for all MS Graph sync operations with conflict tracking';
COMMENT ON FUNCTION handle_manager_change_with_sync IS 'Handles manager changes with conflict resolution based on source_of_truth';


