      RAISE EXCEPTION 'FAIL: Invalid transition was allowed';
    END IF;
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'PASS: Invalid transition blocked as expected - %', SQLERRM;
  END;
  
