-- ============================================================
-- Sync financial_records → chart_of_accounts.current_balance
-- ============================================================
-- The trigger matches records by:
--   financial_records.type   ↔  chart_of_accounts.account_type  (revenue/expense)
--   financial_records.category ↔ chart_of_accounts.account_name  (case-insensitive)
--   financial_records.user_id  ↔ chart_of_accounts.user_id
-- ============================================================

-- 1. Trigger function
CREATE OR REPLACE FUNCTION grxbooks.sync_coa_balance_from_financial_records()
RETURNS TRIGGER
LANGUAGE plpgsql
SET search_path = grxbooks
AS $$
BEGIN
  -- Handle DELETE — subtract the old amount
  IF TG_OP = 'DELETE' THEN
    UPDATE grxbooks.chart_of_accounts
    SET current_balance = current_balance - OLD.amount,
        updated_at = now()
    WHERE user_id = OLD.user_id
      AND account_type = OLD.type
      AND LOWER(account_name) = LOWER(OLD.category);
    RETURN OLD;
  END IF;

  -- Handle UPDATE — reverse old, apply new
  IF TG_OP = 'UPDATE' THEN
    -- Reverse the old entry
    UPDATE grxbooks.chart_of_accounts
    SET current_balance = current_balance - OLD.amount,
        updated_at = now()
    WHERE user_id = OLD.user_id
      AND account_type = OLD.type
      AND LOWER(account_name) = LOWER(OLD.category);

    -- Apply the new entry
    UPDATE grxbooks.chart_of_accounts
    SET current_balance = current_balance + NEW.amount,
        updated_at = now()
    WHERE user_id = NEW.user_id
      AND account_type = NEW.type
      AND LOWER(account_name) = LOWER(NEW.category);

    RETURN NEW;
  END IF;

  -- Handle INSERT — add the new amount
  IF TG_OP = 'INSERT' THEN
    UPDATE grxbooks.chart_of_accounts
    SET current_balance = current_balance + NEW.amount,
        updated_at = now()
    WHERE user_id = NEW.user_id
      AND account_type = NEW.type
      AND LOWER(account_name) = LOWER(NEW.category);
    RETURN NEW;
  END IF;

  RETURN NULL;
END;
$$;

-- 2. Attach the trigger to financial_records
DROP TRIGGER IF EXISTS trg_sync_coa_balance ON grxbooks.financial_records;

CREATE TRIGGER trg_sync_coa_balance
AFTER INSERT OR UPDATE OR DELETE ON grxbooks.financial_records
FOR EACH ROW
EXECUTE FUNCTION grxbooks.sync_coa_balance_from_financial_records();

-- 3. Backfill: recompute current_balance for all existing CoA accounts
--    from the full financial_records history (per user + type + category)
UPDATE grxbooks.chart_of_accounts coa
SET current_balance = COALESCE(
  (
    SELECT SUM(fr.amount)
    FROM grxbooks.financial_records fr
    WHERE fr.user_id = coa.user_id
      AND fr.type = coa.account_type
      AND LOWER(fr.category) = LOWER(coa.account_name)
  ), 0
),
updated_at = now();


-- Migration: 20260218060400_financial_integrity_phase1_currency_normalization.sql
-- ================================================================================
-- =====================================================================
-- FINANCIAL INTEGRITY SYSTEM - PHASE 1: Currency Normalization
-- =====================================================================
-- Migration: 20260218060400_financial_integrity_phase1_currency_normalization.sql
-- Description: Adds currency normalization to journal lines
-- Dependencies: journal_entries, journal_entry_lines
-- =====================================================================

-- Add currency fields to journal_entry_lines
ALTER TABLE journal_entry_lines
  ADD COLUMN IF NOT EXISTS transaction_currency TEXT DEFAULT 'USD' NOT NULL,
  ADD COLUMN IF NOT EXISTS exchange_rate NUMERIC(15,6) DEFAULT 1.0 NOT NULL,
  ADD COLUMN IF NOT EXISTS base_currency_amount NUMERIC(15,2);

-- Add posting_date as canonical financial date to journal_entries
ALTER TABLE journal_entries
  ADD COLUMN IF NOT EXISTS posting_date DATE;

-- Backfill posting_date with entry_date for existing records
UPDATE journal_entries
SET posting_date = entry_date
WHERE posting_date IS NULL;

-- Make posting_date NOT NULL after backfill
ALTER TABLE journal_entries
  ALTER COLUMN posting_date SET NOT NULL;

-- Backfill base_currency_amount for existing records
-- For USD transactions with rate 1.0, base amount = debit or credit
UPDATE journal_entry_lines
SET base_currency_amount = CASE 
  WHEN debit > 0 THEN debit 
  ELSE credit 
END
WHERE base_currency_amount IS NULL;

-- Make base_currency_amount NOT NULL after backfill
ALTER TABLE journal_entry_lines
  ALTER COLUMN base_currency_amount SET NOT NULL;

-- Add constraint to ensure exchange_rate is positive
ALTER TABLE journal_entry_lines
  ADD CONSTRAINT check_positive_exchange_rate 
  CHECK (exchange_rate > 0);

-- Add constraint to ensure currency code is valid (ISO 4217)
ALTER TABLE journal_entry_lines
  ADD CONSTRAINT check_valid_currency_code 
  CHECK (transaction_currency ~ '^[A-Z]{3}$');

-- Create index on posting_date for performance
CREATE INDEX IF NOT EXISTS idx_journal_entries_posting_date 
  ON journal_entries(posting_date DESC);

-- Create index on transaction_currency for reporting
CREATE INDEX IF NOT EXISTS idx_journal_entry_lines_currency 
  ON journal_entry_lines(transaction_currency);

-- Add comment for documentation
COMMENT ON COLUMN journal_entry_lines.transaction_currency IS 
  'ISO 4217 currency code for the original transaction';
COMMENT ON COLUMN journal_entry_lines.exchange_rate IS 
  'Exchange rate to base currency at transaction time';
COMMENT ON COLUMN journal_entry_lines.base_currency_amount IS 
  'Amount in base currency (USD) for consistent aggregation';
COMMENT ON COLUMN journal_entries.posting_date IS 
  'Canonical financial truth date - use this for all reports';

-- =====================================================================
-- FUNCTION: Calculate Base Currency Amount
-- =====================================================================
CREATE OR REPLACE FUNCTION calculate_base_currency_amount()
RETURNS TRIGGER AS $$
BEGIN
  -- Calculate base currency amount based on debit/credit and exchange rate
  IF NEW.debit > 0 THEN
    NEW.base_currency_amount := NEW.debit * NEW.exchange_rate;
  ELSE
    NEW.base_currency_amount := NEW.credit * NEW.exchange_rate;
  END IF;
  
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger to auto-calculate base currency amount
DROP TRIGGER IF EXISTS trg_calculate_base_currency_amount ON journal_entry_lines;
CREATE TRIGGER trg_calculate_base_currency_amount
  BEFORE INSERT OR UPDATE ON journal_entry_lines
  FOR EACH ROW
  EXECUTE FUNCTION calculate_base_currency_amount();

-- =====================================================================
-- Grant permissions
-- =====================================================================
GRANT SELECT ON journal_entry_lines TO authenticated;
GRANT SELECT ON journal_entries TO authenticated;


-- Migration: 20260218060500_financial_integrity_phase2_canonical_views.sql
-- ================================================================================
-- =====================================================================
-- FINANCIAL INTEGRITY SYSTEM - PHASE 2: Canonical Views
-- =====================================================================
-- Migration: 20260218060500_financial_integrity_phase2_canonical_views.sql
-- Description: Creates canonical views as single source of truth
-- Dependencies: journal_entries, journal_entry_lines, chart_of_accounts
-- =====================================================================

-- =====================================================================
-- VIEW: v_trial_balance
-- Purpose: Single source of truth for account balances
-- =====================================================================
CREATE OR REPLACE VIEW v_trial_balance AS
SELECT
  je.organization_id,
  jel.account_id,
  coa.account_code,
  coa.account_name,
  coa.account_type,
  SUM(jel.base_currency_amount * CASE WHEN jel.debit > 0 THEN 1 ELSE -1 END) AS balance,
  SUM(CASE WHEN jel.debit > 0 THEN jel.base_currency_amount ELSE 0 END) AS total_debits,
  SUM(CASE WHEN jel.credit > 0 THEN jel.base_currency_amount ELSE 0 END) AS total_credits,
  COUNT(DISTINCT je.id) AS entry_count,
  MAX(je.posting_date) AS last_posting_date
FROM journal_entry_lines jel
JOIN journal_entries je ON jel.entry_id = je.id
JOIN chart_of_accounts coa ON jel.account_id = coa.id
WHERE je.posted = true
  AND je.reversed = false
  AND je.deleted_at IS NULL
  AND je.organization_id IS NOT NULL
GROUP BY 
  je.organization_id,
  jel.account_id,
  coa.account_code,
  coa.account_name,
  coa.account_type;

COMMENT ON VIEW v_trial_balance IS 
  'Canonical trial balance - ALL financial reporting MUST derive from this view';

-- =====================================================================
-- VIEW: v_profit_and_loss
-- Purpose: Income statement derived from revenue and expense accounts
-- =====================================================================
CREATE OR REPLACE VIEW v_profit_and_loss AS
SELECT
  je.organization_id,
  jel.account_id,
  coa.account_code,
  coa.account_name,
  coa.account_type,
  coa.category,
  CASE 
    WHEN coa.account_type = 'revenue' THEN 'Revenue'
    WHEN coa.account_type = 'expense' THEN 'Expense'
    WHEN coa.account_type = 'cost_of_goods_sold' THEN 'Cost of Goods Sold'
    ELSE 'Other'
  END AS section,
  -- Revenue: credits increase, debits decrease
  -- Expenses: debits increase, credits decrease
  SUM(
    CASE 
      WHEN coa.account_type = 'revenue' THEN 
        jel.base_currency_amount * CASE WHEN jel.credit > 0 THEN 1 ELSE -1 END
      WHEN coa.account_type IN ('expense', 'cost_of_goods_sold') THEN 
        jel.base_currency_amount * CASE WHEN jel.debit > 0 THEN 1 ELSE -1 END
      ELSE 0
    END
  ) AS amount,
  COUNT(DISTINCT je.id) AS transaction_count,
  MIN(je.posting_date) AS period_start,
  MAX(je.posting_date) AS period_end
FROM journal_entry_lines jel
JOIN journal_entries je ON jel.entry_id = je.id
JOIN chart_of_accounts coa ON jel.account_id = coa.id
WHERE je.posted = true
  AND je.reversed = false
  AND je.deleted_at IS NULL
  AND je.organization_id IS NOT NULL
  AND coa.account_type IN ('revenue', 'expense', 'cost_of_goods_sold')
GROUP BY 
  je.organization_id,
  jel.account_id,
  coa.account_code,
  coa.account_name,
  coa.account_type,
  coa.category;

COMMENT ON VIEW v_profit_and_loss IS 
  'Canonical P&L - Dashboard revenue/expense MUST match this view';

-- =====================================================================
-- VIEW: v_cash_position
-- Purpose: Cash and bank account balances
-- =====================================================================
CREATE OR REPLACE VIEW v_cash_position AS
SELECT
  je.organization_id,
  jel.account_id,
  coa.account_code,
  coa.account_name,
  coa.category,
  SUM(jel.base_currency_amount * CASE WHEN jel.debit > 0 THEN 1 ELSE -1 END) AS balance,
  COUNT(DISTINCT je.id) AS transaction_count,
  MAX(je.posting_date) AS last_transaction_date
FROM journal_entry_lines jel
JOIN journal_entries je ON jel.entry_id = je.id
JOIN chart_of_accounts coa ON jel.account_id = coa.id
WHERE je.posted = true
  AND je.reversed = false
  AND je.deleted_at IS NULL
  AND je.organization_id IS NOT NULL
  AND coa.account_type = 'asset'
  AND (coa.category ILIKE '%cash%' OR coa.category ILIKE '%bank%')
GROUP BY 
  je.organization_id,
  jel.account_id,
  coa.account_code,
  coa.account_name,
  coa.category;

COMMENT ON VIEW v_cash_position IS 
  'Canonical cash position - Banking dashboard MUST use this view';

-- =====================================================================
-- VIEW: v_accounts_receivable
-- Purpose: AR balances from AR control account
-- =====================================================================
CREATE OR REPLACE VIEW v_accounts_receivable AS
SELECT
  je.organization_id,
  jel.account_id,
  coa.account_code,
  coa.account_name,
  SUM(jel.base_currency_amount * CASE WHEN jel.debit > 0 THEN 1 ELSE -1 END) AS balance,
  COUNT(DISTINCT je.id) AS invoice_count,
  MAX(je.posting_date) AS last_invoice_date,
  -- Age buckets based on posting date
  SUM(CASE 
    WHEN CURRENT_DATE - je.posting_date <= 30 THEN 
      jel.base_currency_amount * CASE WHEN jel.debit > 0 THEN 1 ELSE -1 END
    ELSE 0 
  END) AS current_amount,
  SUM(CASE 
    WHEN CURRENT_DATE - je.posting_date BETWEEN 31 AND 60 THEN 
      jel.base_currency_amount * CASE WHEN jel.debit > 0 THEN 1 ELSE -1 END
    ELSE 0 
  END) AS days_31_60,
  SUM(CASE 
    WHEN CURRENT_DATE - je.posting_date BETWEEN 61 AND 90 THEN 
      jel.base_currency_amount * CASE WHEN jel.debit > 0 THEN 1 ELSE -1 END
    ELSE 0 
  END) AS days_61_90,
  SUM(CASE 
    WHEN CURRENT_DATE - je.posting_date > 90 THEN 
      jel.base_currency_amount * CASE WHEN jel.debit > 0 THEN 1 ELSE -1 END
    ELSE 0 
  END) AS over_90_days
FROM journal_entry_lines jel
JOIN journal_entries je ON jel.entry_id = je.id
JOIN chart_of_accounts coa ON jel.account_id = coa.id
WHERE je.posted = true
  AND je.reversed = false
  AND je.deleted_at IS NULL
  AND je.organization_id IS NOT NULL
  AND coa.account_type = 'asset'
  AND (coa.account_name ILIKE '%accounts receivable%' OR coa.account_code LIKE '1200%')
GROUP BY 
  je.organization_id,
  jel.account_id,
  coa.account_code,
  coa.account_name;

COMMENT ON VIEW v_accounts_receivable IS 
  'Canonical AR - Invoicing dashboard MUST use this view, not invoice table aggregates';

-- =====================================================================
-- VIEW: v_accounts_payable
-- Purpose: AP balances from AP control account
-- =====================================================================
CREATE OR REPLACE VIEW v_accounts_payable AS
SELECT
  je.organization_id,
  jel.account_id,
  coa.account_code,
  coa.account_name,
  SUM(jel.base_currency_amount * CASE WHEN jel.credit > 0 THEN 1 ELSE -1 END) AS balance,
  COUNT(DISTINCT je.id) AS bill_count,
  MAX(je.posting_date) AS last_bill_date,
  -- Age buckets
  SUM(CASE 
    WHEN CURRENT_DATE - je.posting_date <= 30 THEN 
      jel.base_currency_amount * CASE WHEN jel.credit > 0 THEN 1 ELSE -1 END
    ELSE 0 
  END) AS current_amount,
  SUM(CASE 
    WHEN CURRENT_DATE - je.posting_date BETWEEN 31 AND 60 THEN 
      jel.base_currency_amount * CASE WHEN jel.credit > 0 THEN 1 ELSE -1 END
    ELSE 0 
  END) AS days_31_60,
  SUM(CASE 
    WHEN CURRENT_DATE - je.posting_date > 60 THEN 
      jel.base_currency_amount * CASE WHEN jel.credit > 0 THEN 1 ELSE -1 END
    ELSE 0 
  END) AS over_60_days
FROM journal_entry_lines jel
JOIN journal_entries je ON jel.entry_id = je.id
JOIN chart_of_accounts coa ON jel.account_id = coa.id
WHERE je.posted = true
  AND je.reversed = false
  AND je.deleted_at IS NULL
  AND je.organization_id IS NOT NULL
  AND coa.account_type = 'liability'
  AND (coa.account_name ILIKE '%accounts payable%' OR coa.account_code LIKE '2100%')
GROUP BY 
  je.organization_id,
  jel.account_id,
  coa.account_code,
  coa.account_name;

COMMENT ON VIEW v_accounts_payable IS 
  'Canonical AP - Bills dashboard MUST use this view, not bill table aggregates';

-- =====================================================================
-- Create indexes to optimize view performance
-- =====================================================================
CREATE INDEX IF NOT EXISTS idx_journal_entries_posted_not_reversed 
  ON journal_entries(posted, reversed, deleted_at) 
  WHERE posted = true AND reversed = false AND deleted_at IS NULL;

CREATE INDEX IF NOT EXISTS idx_journal_entry_lines_account_base_amount 
  ON journal_entry_lines(account_id, base_currency_amount);

CREATE INDEX IF NOT EXISTS idx_chart_of_accounts_type_category 
  ON chart_of_accounts(account_type, category);

-- =====================================================================
-- Grant permissions
-- =====================================================================
GRANT SELECT ON v_trial_balance TO authenticated;
GRANT SELECT ON v_profit_and_loss TO authenticated;
GRANT SELECT ON v_cash_position TO authenticated;
GRANT SELECT ON v_accounts_receivable TO authenticated;
GRANT SELECT ON v_accounts_payable TO authenticated;


-- Migration: 20260218060600_financial_integrity_phase3_reconciliation_engine.sql
-- ================================================================================
-- =====================================================================
-- FINANCIAL INTEGRITY SYSTEM - PHASE 3: Reconciliation Engine
-- =====================================================================
-- Migration: 20260218060600_financial_integrity_phase3_reconciliation_engine.sql
-- Description: Automated reconciliation and integrity checking
-- Dependencies: canonical views, invoices, bills, payments
-- =====================================================================

-- =====================================================================
-- TABLE: financial_integrity_alerts
-- =====================================================================
CREATE TABLE IF NOT EXISTS financial_integrity_alerts (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID NOT NULL,
  alert_type TEXT NOT NULL CHECK (alert_type IN (
    'ar_mismatch',
    'ap_mismatch', 
    'cash_mismatch',
    'revenue_mismatch',
    'expense_mismatch',
    'unbalanced_entry',
    'orphaned_document'
  )),
  severity TEXT NOT NULL CHECK (severity IN ('critical', 'high', 'medium', 'low')),
  title TEXT NOT NULL,
  description TEXT NOT NULL,
  expected_value NUMERIC(15,2),
  actual_value NUMERIC(15,2),
  variance NUMERIC(15,2),
  variance_percentage NUMERIC(5,2),
  reference_type TEXT,
  reference_id UUID,
  detected_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(),
  resolved_at TIMESTAMP WITH TIME ZONE,
  resolved_by UUID REFERENCES auth.users(id),
  resolution_notes TEXT,
  metadata JSONB,
  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now()
);

-- Create indexes
CREATE INDEX idx_integrity_alerts_org_unresolved 
  ON financial_integrity_alerts(organization_id, detected_at DESC) 
  WHERE resolved_at IS NULL;

CREATE INDEX idx_integrity_alerts_type_severity 
  ON financial_integrity_alerts(alert_type, severity, detected_at DESC);

-- Enable RLS
ALTER TABLE financial_integrity_alerts ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view alerts for their organization"
ON financial_integrity_alerts FOR SELECT
USING (
  EXISTS (
    SELECT 1 FROM organization_members om
    WHERE om.organization_id = financial_integrity_alerts.organization_id
    AND om.user_id = auth.uid()
  )
);

COMMENT ON TABLE financial_integrity_alerts IS 
  'Stores financial data integrity violations and reconciliation mismatches';

-- =====================================================================
-- TABLE: reconciliation_history
-- =====================================================================
CREATE TABLE IF NOT EXISTS reconciliation_history (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id UUID NOT NULL,
  reconciliation_type TEXT NOT NULL CHECK (reconciliation_type IN (
    'ar_subledger',
    'ap_subledger',
    'cash_bank',
    'revenue_ledger',
    'expense_ledger',
    'full_system'
  )),
  status TEXT NOT NULL CHECK (status IN ('success', 'warning', 'failed')),
  alerts_created INTEGER NOT NULL DEFAULT 0,
  records_checked INTEGER NOT NULL DEFAULT 0,
  variance_found NUMERIC(15,2),
  run_by UUID REFERENCES auth.users(id),
  run_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(),
  duration_ms INTEGER,
  metadata JSONB,
  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now()
);

CREATE INDEX idx_reconciliation_history_org_date 
  ON reconciliation_history(organization_id, run_at DESC);

-- Enable RLS
ALTER TABLE reconciliation_history ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view reconciliation history for their organization"
ON reconciliation_history FOR SELECT
USING (
  EXISTS (
    SELECT 1 FROM organization_members om
    WHERE om.organization_id = reconciliation_history.organization_id
    AND om.user_id = auth.uid()
  )
);

-- =====================================================================
-- FUNCTION: Reconcile AR Subledger vs Control Account
-- =====================================================================
CREATE OR REPLACE FUNCTION reconcile_ar_subledger(p_organization_id UUID)
RETURNS TABLE (
  status TEXT,
  subledger_total NUMERIC,
  control_account_total NUMERIC,
  variance NUMERIC,
  alert_id UUID
) AS $$
DECLARE
  v_invoice_total NUMERIC;
  v_ar_control_total NUMERIC;
  v_variance NUMERIC;
  v_alert_id UUID;
BEGIN
  -- Calculate total from invoice subledger (posted invoices minus payments)
  SELECT COALESCE(SUM(
    CASE 
      WHEN i.status IN ('sent', 'overdue') THEN i.total_amount
      WHEN i.status = 'paid' THEN 0
      ELSE 0
    END
  ), 0)
  INTO v_invoice_total
  FROM invoices i
  WHERE i.organization_id = p_organization_id;

  -- Calculate total from AR control account in trial balance
  SELECT COALESCE(SUM(balance), 0)
  INTO v_ar_control_total
  FROM v_accounts_receivable
  WHERE organization_id = p_organization_id;

  -- Calculate variance
  v_variance := v_invoice_total - v_ar_control_total;

  -- If variance exists, create alert
  IF ABS(v_variance) > 0.01 THEN
    INSERT INTO financial_integrity_alerts (
      organization_id,
      alert_type,
      severity,
      title,
      description,
      expected_value,
      actual_value,
      variance,
      variance_percentage,
      metadata
    ) VALUES (
      p_organization_id,
      'ar_mismatch',
      CASE 
        WHEN ABS(v_variance) > 1000 THEN 'critical'
        WHEN ABS(v_variance) > 100 THEN 'high'
        ELSE 'medium'
      END,
      'AR Subledger Mismatch',
      'Accounts Receivable subledger (invoices) does not match AR control account balance',
      v_ar_control_total,
      v_invoice_total,
      v_variance,
      CASE WHEN v_ar_control_total != 0 THEN (v_variance / v_ar_control_total * 100) ELSE 0 END,
      jsonb_build_object(
        'invoice_total', v_invoice_total,
        'control_total', v_ar_control_total
      )
    )
    RETURNING id INTO v_alert_id;

    RETURN QUERY SELECT 
      'mismatch'::TEXT,
      v_invoice_total,
      v_ar_control_total,
      v_variance,
      v_alert_id;
  ELSE
    RETURN QUERY SELECT 
      'balanced'::TEXT,
      v_invoice_total,
      v_ar_control_total,
      0::NUMERIC,
      NULL::UUID;
  END IF;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- =====================================================================
-- FUNCTION: Reconcile AP Subledger vs Control Account
-- =====================================================================
CREATE OR REPLACE FUNCTION reconcile_ap_subledger(p_organization_id UUID)
RETURNS TABLE (
  status TEXT,
  subledger_total NUMERIC,
  control_account_total NUMERIC,
  variance NUMERIC,
  alert_id UUID
) AS $$
DECLARE
  v_bill_total NUMERIC;
  v_ap_control_total NUMERIC;
  v_variance NUMERIC;
  v_alert_id UUID;
BEGIN
  -- Calculate total from bill subledger (unpaid bills)
  SELECT COALESCE(SUM(
    CASE 
      WHEN b.status IN ('approved', 'pending_payment') THEN b.total_amount
      WHEN b.status = 'paid' THEN 0
      ELSE 0
    END
  ), 0)
  INTO v_bill_total
  FROM bills b
  WHERE b.organization_id = p_organization_id;

  -- Calculate total from AP control account
  SELECT COALESCE(SUM(balance), 0)
  INTO v_ap_control_total
  FROM v_accounts_payable
  WHERE organization_id = p_organization_id;

  -- Calculate variance
  v_variance := v_bill_total - v_ap_control_total;

  -- If variance exists, create alert
  IF ABS(v_variance) > 0.01 THEN
    INSERT INTO financial_integrity_alerts (
      organization_id,
      alert_type,
      severity,
      title,
      description,
      expected_value,
      actual_value,
      variance,
      variance_percentage,
      metadata
    ) VALUES (
      p_organization_id,
      'ap_mismatch',
      CASE 
        WHEN ABS(v_variance) > 1000 THEN 'critical'
        WHEN ABS(v_variance) > 100 THEN 'high'
        ELSE 'medium'
      END,
      'AP Subledger Mismatch',
      'Accounts Payable subledger (bills) does not match AP control account balance',
      v_ap_control_total,
      v_bill_total,
      v_variance,
      CASE WHEN v_ap_control_total != 0 THEN (v_variance / v_ap_control_total * 100) ELSE 0 END,
      jsonb_build_object(
        'bill_total', v_bill_total,
        'control_total', v_ap_control_total
      )
    )
    RETURNING id INTO v_alert_id;

    RETURN QUERY SELECT 
      'mismatch'::TEXT,
      v_bill_total,
      v_ap_control_total,
      v_variance,
      v_alert_id;
  ELSE
    RETURN QUERY SELECT 
      'balanced'::TEXT,
      v_bill_total,
      v_ap_control_total,
      0::NUMERIC,
      NULL::UUID;
  END IF;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- =====================================================================
-- FUNCTION: Run Full System Reconciliation
-- =====================================================================
CREATE OR REPLACE FUNCTION run_full_reconciliation(p_organization_id UUID)
RETURNS TABLE (
  reconciliation_type TEXT,
  status TEXT,
  variance NUMERIC,
  alert_count INTEGER
) AS $$
DECLARE
  v_start_time TIMESTAMP;
  v_ar_status TEXT;
  v_ap_status TEXT;
  v_ar_variance NUMERIC;
  v_ap_variance NUMERIC;
  v_total_alerts INTEGER := 0;
  v_recon_id UUID;
BEGIN
  v_start_time := clock_timestamp();

  -- Reconcile AR
  SELECT r.status, r.variance INTO v_ar_status, v_ar_variance
  FROM reconcile_ar_subledger(p_organization_id) r;
  
  IF v_ar_status = 'mismatch' THEN
    v_total_alerts := v_total_alerts + 1;
  END IF;

  -- Reconcile AP
  SELECT r.status, r.variance INTO v_ap_status, v_ap_variance
  FROM reconcile_ap_subledger(p_organization_id) r;
  
  IF v_ap_status = 'mismatch' THEN
    v_total_alerts := v_total_alerts + 1;
  END IF;

  -- Record reconciliation history
  INSERT INTO reconciliation_history (
    organization_id,
    reconciliation_type,
    status,
    alerts_created,
    records_checked,
    variance_found,
    run_by,
    duration_ms,
    metadata
  ) VALUES (
    p_organization_id,
    'full_system',
    CASE WHEN v_total_alerts = 0 THEN 'success' ELSE 'warning' END,
    v_total_alerts,
    2, -- AR and AP
    COALESCE(ABS(v_ar_variance), 0) + COALESCE(ABS(v_ap_variance), 0),
    auth.uid(),
    EXTRACT(MILLISECONDS FROM clock_timestamp() - v_start_time)::INTEGER,
    jsonb_build_object(
      'ar_status', v_ar_status,
      'ap_status', v_ap_status,
      'ar_variance', v_ar_variance,
      'ap_variance', v_ap_variance
    )
  )
  RETURNING id INTO v_recon_id;

  -- Return results
  RETURN QUERY 
  SELECT 'AR'::TEXT, v_ar_status, v_ar_variance, CASE WHEN v_ar_status = 'mismatch' THEN 1 ELSE 0 END
  UNION ALL
  SELECT 'AP'::TEXT, v_ap_status, v_ap_variance, CASE WHEN v_ap_status = 'mismatch' THEN 1 ELSE 0 END;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- =====================================================================
-- FUNCTION: Get Latest Reconciliation Status
-- =====================================================================
CREATE OR REPLACE FUNCTION get_latest_reconciliation_status(p_organization_id UUID)
RETURNS TABLE (
  last_reconciled_at TIMESTAMP WITH TIME ZONE,
  status TEXT,
  unresolved_alerts INTEGER,
  critical_alerts INTEGER
) AS $$
BEGIN
  RETURN QUERY
  SELECT 
    (SELECT MAX(run_at) 
     FROM reconciliation_history 
     WHERE organization_id = p_organization_id) as last_reconciled_at,
    (SELECT status 
     FROM reconciliation_history 
     WHERE organization_id = p_organization_id 
     ORDER BY run_at DESC 
     LIMIT 1) as status,
    (SELECT COUNT(*)::INTEGER 
     FROM financial_integrity_alerts 
     WHERE organization_id = p_organization_id 
     AND resolved_at IS NULL) as unresolved_alerts,
    (SELECT COUNT(*)::INTEGER 
     FROM financial_integrity_alerts 
     WHERE organization_id = p_organization_id 
     AND resolved_at IS NULL 
     AND severity = 'critical') as critical_alerts;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

-- =====================================================================
-- Grant permissions
-- =====================================================================
GRANT SELECT ON financial_integrity_alerts TO authenticated;
GRANT SELECT ON reconciliation_history TO authenticated;
GRANT EXECUTE ON FUNCTION reconcile_ar_subledger(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION reconcile_ap_subledger(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION run_full_reconciliation(UUID) TO authenticated;
GRANT EXECUTE ON FUNCTION get_latest_reconciliation_status(UUID) TO authenticated;


-- Migration: 20260218060700_financial_integrity_phase4_posting_constraints.sql
-- ================================================================================
-- =====================================================================
-- FINANCIAL INTEGRITY SYSTEM - PHASE 4: Posting Validation Constraints
-- =====================================================================
-- Migration: 20260218060700_financial_integrity_phase4_posting_constraints.sql
-- Description: Enforce that financial documents cannot post without journal entries
-- Dependencies: journal_entries, invoices, bills, payments
-- =====================================================================

-- =====================================================================
-- FUNCTION: Validate Invoice Has Journal Entry Before Posting
-- =====================================================================
CREATE OR REPLACE FUNCTION validate_invoice_has_journal()
RETURNS TRIGGER AS $$
BEGIN
  -- Only validate when moving to 'sent' or 'paid' status
  IF NEW.status IN ('sent', 'paid') AND (OLD.status IS NULL OR OLD.status = 'draft') THEN
    -- Check if journal entry exists for this invoice
    IF NOT EXISTS (
      SELECT 1 FROM journal_entries
      WHERE reference_type = 'invoice'
      AND reference_id = NEW.id
      AND posted = true
    ) THEN
      RAISE EXCEPTION 'Cannot post invoice without corresponding journal entry. Create journal entry first.'
        USING HINT = 'Invoice must have a posted journal entry before changing status to sent or paid';
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger for invoice posting validation
DROP TRIGGER IF EXISTS trg_validate_invoice_posting ON invoices;
CREATE TRIGGER trg_validate_invoice_posting
  BEFORE UPDATE ON invoices
  FOR EACH ROW
  EXECUTE FUNCTION validate_invoice_has_journal();

-- =====================================================================
-- FUNCTION: Validate Bill Has Journal Entry Before Approval
-- =====================================================================
CREATE OR REPLACE FUNCTION validate_bill_has_journal()
RETURNS TRIGGER AS $$
BEGIN
  -- Only validate when moving to 'approved' or 'paid' status
  IF NEW.status IN ('approved', 'paid') AND (OLD.status IS NULL OR OLD.status IN ('draft', 'pending_approval')) THEN
    -- Check if journal entry exists for this bill
    IF NOT EXISTS (
      SELECT 1 FROM journal_entries
      WHERE reference_type = 'bill'
      AND reference_id = NEW.id
      AND posted = true
    ) THEN
      RAISE EXCEPTION 'Cannot approve/pay bill without corresponding journal entry. Create journal entry first.'
        USING HINT = 'Bill must have a posted journal entry before changing status to approved or paid';
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger for bill posting validation
DROP TRIGGER IF EXISTS trg_validate_bill_posting ON bills;
CREATE TRIGGER trg_validate_bill_posting
  BEFORE UPDATE ON bills
  FOR EACH ROW
  EXECUTE FUNCTION validate_bill_has_journal();

-- =====================================================================
-- FUNCTION: Validate Payment Has Journal Entry Before Completion
-- =====================================================================
CREATE OR REPLACE FUNCTION validate_payment_has_journal()
RETURNS TRIGGER AS $$
BEGIN
  -- Only validate when moving to 'completed' status
  IF NEW.status = 'completed' AND (OLD.status IS NULL OR OLD.status IN ('pending', 'processing')) THEN
    -- Check if journal entry exists for this payment
    IF NOT EXISTS (
      SELECT 1 FROM journal_entries
      WHERE reference_type = 'payment'
      AND reference_id = NEW.id
      AND posted = true
    ) THEN
      RAISE EXCEPTION 'Cannot complete payment without corresponding journal entry. Create journal entry first.'
        USING HINT = 'Payment must have a posted journal entry before changing status to completed';
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create trigger for payment posting validation (if payments table exists)
DO $$
BEGIN
  IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'payments') THEN
    DROP TRIGGER IF EXISTS trg_validate_payment_posting ON payments;
    EXECUTE 'CREATE TRIGGER trg_validate_payment_posting
      BEFORE UPDATE ON payments
      FOR EACH ROW
      EXECUTE FUNCTION validate_payment_has_journal()';
  END IF;
END $$;

-- =====================================================================
-- FUNCTION: Prevent Soft Delete of Posted Financial Records
-- =====================================================================
CREATE OR REPLACE FUNCTION prevent_posted_soft_delete()
RETURNS TRIGGER AS $$
BEGIN
  -- Check if we're doing a soft delete (setting deleted_at)
  IF NEW.deleted_at IS NOT NULL AND OLD.deleted_at IS NULL THEN
    -- For invoices
    IF TG_TABLE_NAME = 'invoices' AND NEW.status IN ('sent', 'paid') THEN
      RAISE EXCEPTION 'Cannot delete posted invoice. Create a reversal journal entry instead.'
        USING HINT = 'Posted invoices must be reversed through journal entries';
    END IF;
    
    -- For bills
    IF TG_TABLE_NAME = 'bills' AND NEW.status IN ('approved', 'paid') THEN
      RAISE EXCEPTION 'Cannot delete posted bill. Create a reversal journal entry instead.'
        USING HINT = 'Posted bills must be reversed through journal entries';
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Create triggers for soft delete prevention
DROP TRIGGER IF EXISTS trg_prevent_invoice_soft_delete ON invoices;
CREATE TRIGGER trg_prevent_invoice_soft_delete
  BEFORE UPDATE ON invoices
  FOR EACH ROW
  EXECUTE FUNCTION prevent_posted_soft_delete();

DROP TRIGGER IF EXISTS trg_prevent_bill_soft_delete ON bills;
CREATE TRIGGER trg_prevent_bill_soft_delete
  BEFORE UPDATE ON bills
  FOR EACH ROW
  EXECUTE FUNCTION prevent_posted_soft_delete();

-- =====================================================================
-- FUNCTION: Enforce Organization Isolation in Journal Entries
-- =====================================================================
-- Note: We cannot add a NOT NULL constraint on organization_id without a migration
-- strategy for existing data. Instead, we create a validation function.

CREATE OR REPLACE FUNCTION validate_organization_context()
RETURNS TRIGGER AS $$
BEGIN
  -- For new records created after this migration, strongly encourage organization_id
  IF NEW.organization_id IS NULL AND NEW.user_id IS NOT NULL THEN
    -- Try to get organization from user's default organization or create one
    -- This is a soft enforcement - we log a warning but allow the operation
    RAISE WARNING 'Journal entry created without organization_id. Consider setting organization_id for proper multi-tenant isolation.';
  END IF;
  
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_validate_organization_context ON journal_entries;
CREATE TRIGGER trg_validate_organization_context
  BEFORE INSERT ON journal_entries
  FOR EACH ROW
  EXECUTE FUNCTION validate_organization_context();

-- =====================================================================
-- Create helper view for orphaned financial documents
-- (documents without corresponding journal entries)
-- =====================================================================
CREATE OR REPLACE VIEW v_orphaned_financial_documents AS
-- Invoices without journal entries
SELECT 
  'invoice' as document_type,
  i.id as document_id,
  i.invoice_number as document_number,
  i.total_amount as amount,
  i.status,
  i.created_at,
  'Missing journal entry for posted invoice' as issue
FROM invoices i
WHERE i.status IN ('sent', 'paid')
AND NOT EXISTS (
  SELECT 1 FROM journal_entries je
  WHERE je.reference_type = 'invoice'
  AND je.reference_id = i.id
  AND je.posted = true
)
AND i.deleted_at IS NULL

UNION ALL

-- Bills without journal entries
SELECT 
  'bill' as document_type,
  b.id as document_id,
  b.bill_number as document_number,
  b.total_amount as amount,
  b.status,
  b.created_at,
  'Missing journal entry for posted bill' as issue
FROM bills b
WHERE b.status IN ('approved', 'paid')
AND NOT EXISTS (
  SELECT 1 FROM journal_entries je
  WHERE je.reference_type = 'bill'
  AND je.reference_id = b.id
  AND je.posted = true
)
AND b.deleted_at IS NULL;

COMMENT ON VIEW v_orphaned_financial_documents IS 
  'Identifies posted invoices/bills without corresponding journal entries - data integrity issue';

-- =====================================================================
-- Grant permissions
-- =====================================================================
GRANT SELECT ON v_orphaned_financial_documents TO authenticated;


