CREATE TRIGGER trg_identity_sync_leave_balances
  BEFORE INSERT OR UPDATE ON grxbooks.leave_balances
  FOR EACH ROW EXECUTE FUNCTION grxbooks.validate_identity_sync();

CREATE TRIGGER trg_identity_sync_payroll_records
  BEFORE INSERT OR UPDATE ON grxbooks.payroll_records
  FOR EACH ROW EXECUTE FUNCTION grxbooks.validate_identity_sync();

CREATE TRIGGER trg_identity_sync_goal_plans
  BEFORE INSERT OR UPDATE ON grxbooks.goal_plans
  FOR EACH ROW EXECUTE FUNCTION grxbooks.validate_identity_sync();

CREATE TRIGGER trg_identity_sync_reimbursement_requests
  BEFORE INSERT OR UPDATE ON grxbooks.reimbursement_requests
  FOR EACH ROW EXECUTE FUNCTION grxbooks.validate_identity_sync();


