RETURNS UUID
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = grxbooks
AS $$
  SELECT organization_id FROM grxbooks.organization_members
  WHERE user_id = _user_id
  LIMIT 1;
$$;

-- Step 8: Helper function for org membership check
