RETURNS BOOLEAN
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = grxbooks
AS $$
  SELECT EXISTS (
    SELECT 1 FROM grxbooks.organization_members
    WHERE user_id = _user_id AND organization_id = _org_id
  );
$$;

