CREATE OR REPLACE FUNCTION grxbooks.auto_set_organization_id()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = grxbooks
AS $$
BEGIN
  IF NEW.organization_id IS NULL AND NEW.user_id IS NOT NULL THEN
    NEW.organization_id := get_user_organization_id(NEW.user_id);
  END IF;
  RETURN NEW;
END;
$$;

