-- ---- attendance_correction_requests ----
DROP POLICY IF EXISTS "Managers HR Admins can update correction requests" ON grxbooks.attendance_correction_requests;
DROP POLICY IF EXISTS "Managers HR Admins can view all correction requests" ON grxbooks.attendance_correction_requests;

CREATE POLICY "Org managers can update correction requests"
  ON grxbooks.attendance_correction_requests FOR UPDATE
  USING (is_org_admin_hr_or_manager(auth.uid(), organization_id));

CREATE POLICY "Org managers can view all correction requests"
  ON grxbooks.attendance_correction_requests FOR SELECT
  USING (is_org_admin_hr_or_manager(auth.uid(), organization_id));


-- ---- attendance_records ----
DROP POLICY IF EXISTS "Admins HR and Managers can view all attendance" ON grxbooks.attendance_records;
DROP POLICY IF EXISTS "Admins and HR can delete attendance" ON grxbooks.attendance_records;
DROP POLICY IF EXISTS "Admins and HR can insert any attendance" ON grxbooks.attendance_records;
DROP POLICY IF EXISTS "Admins and HR can update attendance" ON grxbooks.attendance_records;

CREATE POLICY "Org admins can view all attendance"
  ON grxbooks.attendance_records FOR SELECT
  USING (is_org_admin_hr_or_manager(auth.uid(), organization_id));

CREATE POLICY "Org admins can delete attendance"
  ON grxbooks.attendance_records FOR DELETE
  USING (is_org_admin_or_hr(auth.uid(), organization_id));

CREATE POLICY "Org admins can insert any attendance"
  ON grxbooks.attendance_records FOR INSERT
  WITH CHECK (is_org_admin_or_hr(auth.uid(), organization_id));

CREATE POLICY "Org admins can update attendance"
  ON grxbooks.attendance_records FOR UPDATE
  USING (is_org_admin_or_hr(auth.uid(), organization_id));


