CREATE OR REPLACE FUNCTION grxbooks.is_org_admin(_user_id uuid, _org_id uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path TO 'public'
AS $$
  SELECT EXISTS (
    SELECT 1 FROM grxbooks.user_roles
    WHERE user_id = _user_id
      AND role = 'admin'
      AND organization_id = _org_id
  );
$$;

