-- ============ GOAL_PLANS ============
DROP POLICY IF EXISTS "Org managers can update direct reports goal plans" ON grxbooks.goal_plans;
DROP POLICY IF EXISTS "Org managers can view all goal plans" ON grxbooks.goal_plans;
DROP POLICY IF EXISTS "Users can create own goal plans" ON grxbooks.goal_plans;
DROP POLICY IF EXISTS "Users can delete own draft goal plans" ON grxbooks.goal_plans;
DROP POLICY IF EXISTS "Users can update own goal plans" ON grxbooks.goal_plans;
DROP POLICY IF EXISTS "Users can view own goal plans" ON grxbooks.goal_plans;

CREATE POLICY "Org managers can view goal plans"
  ON grxbooks.goal_plans FOR SELECT
  USING (is_org_admin_hr_or_manager(auth.uid(), organization_id));

CREATE POLICY "Org managers can update goal plans"
  ON grxbooks.goal_plans FOR UPDATE
  USING (
    is_org_admin_or_hr(auth.uid(), organization_id)
    OR (
      EXISTS (SELECT 1 FROM profiles p WHERE p.id = goal_plans.profile_id AND p.manager_id = get_current_user_profile_id())
      AND organization_id = get_user_organization_id(auth.uid())
    )
  );

CREATE POLICY "Users can create own goal plans"
  ON grxbooks.goal_plans FOR INSERT
  WITH CHECK (auth.uid() = user_id AND organization_id = get_user_organization_id(auth.uid()));

CREATE POLICY "Users can delete own draft goal plans"
  ON grxbooks.goal_plans FOR DELETE
  USING (auth.uid() = user_id AND status = 'draft');

CREATE POLICY "Users can update own goal plans"
  ON grxbooks.goal_plans FOR UPDATE
  USING (auth.uid() = user_id);

CREATE POLICY "Users can view own goal plans"
  ON grxbooks.goal_plans FOR SELECT
  USING (auth.uid() = user_id);

