  USING (EXISTS (
    SELECT 1 FROM quotes q
    WHERE q.id = quote_items.quote_id AND q.user_id = auth.uid()
  ))
  WITH CHECK (EXISTS (
    SELECT 1 FROM quotes q
    WHERE q.id = quote_items.quote_id AND q.user_id = auth.uid()
  ));

