-- ============================================================
-- POSTING TRIGGERS: Auto-post on status change
-- ============================================================

CREATE OR REPLACE FUNCTION grxbooks.trigger_post_invoice()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public'
AS $$
BEGIN
  -- Post when invoice transitions to sent/paid
  IF NEW.status IN ('sent', 'paid') AND (OLD IS NULL OR OLD.status NOT IN ('sent', 'paid')) THEN
    PERFORM post_invoice_journal(NEW.id);
  END IF;
  -- Post payment when transitioning to paid
  IF NEW.status = 'paid' AND (OLD IS NULL OR OLD.status != 'paid') THEN
    PERFORM post_invoice_payment_journal(NEW.id);
  END IF;
  RETURN NEW;
END;
$$;

CREATE OR REPLACE FUNCTION grxbooks.trigger_post_expense()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public'
AS $$
BEGIN
  IF NEW.status = 'approved' AND (OLD IS NULL OR OLD.status != 'approved') THEN
    PERFORM post_expense_journal(NEW.id);
  END IF;
  RETURN NEW;
END;
$$;

CREATE OR REPLACE FUNCTION grxbooks.trigger_post_bill()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public'
AS $$
BEGIN
  IF NEW.status IN ('approved', 'paid') AND (OLD IS NULL OR OLD.status NOT IN ('approved', 'paid')) THEN
    PERFORM post_bill_journal(NEW.id);
  END IF;
  IF NEW.status = 'paid' AND (OLD IS NULL OR OLD.status != 'paid') THEN
    PERFORM post_bill_payment_journal(NEW.id);
  END IF;
  RETURN NEW;
END;
$$;

-- Drop old posting triggers if they exist (replacing legacy engine)
DROP TRIGGER IF EXISTS trg_post_invoice_to_ledger ON grxbooks.invoices;
DROP TRIGGER IF EXISTS trg_post_bill_to_ledger ON grxbooks.bills;
DROP TRIGGER IF EXISTS trg_post_expense_to_ledger ON grxbooks.expenses;

-- Create new posting triggers
CREATE TRIGGER trg_post_invoice_journal
  AFTER INSERT OR UPDATE ON grxbooks.invoices
  FOR EACH ROW
  EXECUTE FUNCTION grxbooks.trigger_post_invoice();

CREATE TRIGGER trg_post_expense_journal
  AFTER INSERT OR UPDATE ON grxbooks.expenses
  FOR EACH ROW
  EXECUTE FUNCTION grxbooks.trigger_post_expense();

CREATE TRIGGER trg_post_bill_journal
  AFTER INSERT OR UPDATE ON grxbooks.bills
  FOR EACH ROW
  EXECUTE FUNCTION grxbooks.trigger_post_bill();

-- Updated_at trigger for gl_accounts
CREATE TRIGGER update_gl_accounts_updated_at
  BEFORE UPDATE ON grxbooks.gl_accounts
  FOR EACH ROW
  EXECUTE FUNCTION grxbooks.update_updated_at_column();


