CREATE INDEX IF NOT EXISTS idx_budgets_org_period
  ON grxbooks.budgets (organization_id, fiscal_period_id);

CREATE INDEX IF NOT EXISTS idx_budgets_account
  ON grxbooks.budgets (account_id);


