-- Prevent modifications to locked payroll runs
CREATE OR REPLACE FUNCTION grxbooks.trg_prevent_locked_payroll_mutation()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = grxbooks
AS $$
BEGIN
  IF OLD.status = 'locked' THEN
    RAISE EXCEPTION 'Cannot modify a locked payroll run';
  END IF;
  RETURN NEW;
END;
$$;

CREATE TRIGGER trg_prevent_locked_payroll_update
  BEFORE UPDATE ON grxbooks.payroll_runs
  FOR EACH ROW
  EXECUTE FUNCTION grxbooks.trg_prevent_locked_payroll_mutation();

-- Prevent modifications to entries of locked runs
CREATE OR REPLACE FUNCTION grxbooks.trg_prevent_locked_entry_mutation()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = grxbooks
AS $$
BEGIN
  IF EXISTS (SELECT 1 FROM payroll_runs WHERE id = OLD.payroll_run_id AND status = 'locked') THEN
    RAISE EXCEPTION 'Cannot modify entries of a locked payroll run';
  END IF;
  RETURN NEW;
END;
$$;

CREATE TRIGGER trg_prevent_locked_entry_update
  BEFORE UPDATE OR DELETE ON grxbooks.payroll_entries
  FOR EACH ROW
  EXECUTE FUNCTION grxbooks.trg_prevent_locked_entry_mutation();

-- Audit trigger for payroll locking
CREATE OR REPLACE FUNCTION grxbooks.trg_audit_payroll_lock()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = grxbooks
AS $$
BEGIN
  IF NEW.status = 'locked' AND OLD.status != 'locked' THEN
    INSERT INTO grxbooks.audit_logs (actor_id, action, entity_type, entity_id, organization_id, metadata)
    VALUES (
      auth.uid(),
      'payroll_locked',
      'payroll_run',
      NEW.id,
      NEW.organization_id,
      jsonb_build_object('pay_period', NEW.pay_period, 'employee_count', NEW.employee_count, 'total_net', NEW.total_net)
    );
  END IF;
  RETURN NEW;
END;
$$;

CREATE TRIGGER trg_audit_payroll_lock
  AFTER UPDATE ON grxbooks.payroll_runs
  FOR EACH ROW
  EXECUTE FUNCTION grxbooks.trg_audit_payroll_lock();


