CREATE TABLE IF NOT EXISTS grxbooks.tax_regimes (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL UNIQUE,
  description TEXT,
  is_default BOOLEAN DEFAULT false,
  financial_year TEXT NOT NULL DEFAULT '2025-2026',
  created_at TIMESTAMPTZ DEFAULT now()
);

ALTER TABLE grxbooks.tax_regimes ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone authenticated can read tax_regimes" ON grxbooks.tax_regimes
  FOR SELECT TO authenticated USING (true);

CREATE TABLE IF NOT EXISTS grxbooks.tax_slabs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  regime_id UUID NOT NULL REFERENCES public.tax_regimes(id) ON DELETE CASCADE,
  income_from NUMERIC NOT NULL DEFAULT 0,
  income_to NUMERIC NOT NULL DEFAULT 0,
  tax_percentage NUMERIC NOT NULL DEFAULT 0,
  cess_percentage NUMERIC NOT NULL DEFAULT 4,
  created_at TIMESTAMPTZ DEFAULT now()
);

ALTER TABLE grxbooks.tax_slabs ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone authenticated can read tax_slabs" ON grxbooks.tax_slabs
  FOR SELECT TO authenticated USING (true);

CREATE TABLE IF NOT EXISTS grxbooks.employee_tax_settings (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  profile_id UUID NOT NULL REFERENCES public.profiles(id),
  organization_id UUID NOT NULL REFERENCES public.organizations(id),
  regime_id UUID REFERENCES public.tax_regimes(id),
  financial_year TEXT NOT NULL DEFAULT '2025-2026',
  declared_80c NUMERIC DEFAULT 0,
  declared_80d NUMERIC DEFAULT 0,
  hra_exemption NUMERIC DEFAULT 0,
  standard_deduction NUMERIC DEFAULT 75000,
  other_deductions NUMERIC DEFAULT 0,
  previous_employer_income NUMERIC DEFAULT 0,
  previous_employer_tds NUMERIC DEFAULT 0,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(profile_id, organization_id, financial_year)
);

ALTER TABLE grxbooks.employee_tax_settings ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Employees can view own tax settings" ON grxbooks.employee_tax_settings
  FOR SELECT TO authenticated
  USING (profile_id = get_current_user_profile_id() OR is_org_admin_or_hr(auth.uid(), organization_id));

CREATE POLICY "Employees can update own tax settings" ON grxbooks.employee_tax_settings
  FOR INSERT TO authenticated
  WITH CHECK (profile_id = get_current_user_profile_id() OR is_org_admin_or_hr(auth.uid(), organization_id));

CREATE POLICY "Employees can modify own tax settings" ON grxbooks.employee_tax_settings
  FOR UPDATE TO authenticated
  USING (profile_id = get_current_user_profile_id() OR is_org_admin_or_hr(auth.uid(), organization_id));

CREATE TABLE IF NOT EXISTS grxbooks.investment_declarations (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  profile_id UUID NOT NULL REFERENCES public.profiles(id),
  organization_id UUID NOT NULL REFERENCES public.organizations(id),
  financial_year TEXT NOT NULL,
  section_type TEXT NOT NULL,
  declared_amount NUMERIC DEFAULT 0,
  approved_amount NUMERIC DEFAULT 0,
  proof_url TEXT,
  status TEXT DEFAULT 'submitted' CHECK (status IN ('submitted','approved','rejected')),
  reviewed_by UUID REFERENCES auth.users(id),
  reviewed_at TIMESTAMPTZ,
  notes TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

ALTER TABLE grxbooks.investment_declarations ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Employees can manage own declarations" ON grxbooks.investment_declarations
  FOR ALL TO authenticated
  USING (profile_id = get_current_user_profile_id() OR is_org_admin_or_hr(auth.uid(), organization_id))
  WITH CHECK (profile_id = get_current_user_profile_id() OR is_org_admin_or_hr(auth.uid(), organization_id));

