  hr_reviewed_at TIMESTAMPTZ,
  hr_reviewed_by UUID,
  hr_notes TEXT,
  -- Finance step
  finance_reviewed_at TIMESTAMPTZ,
  finance_reviewed_by UUID,
  finance_notes TEXT,
  -- Resolution
  resolved_at TIMESTAMPTZ,
  resolution_notes TEXT,
  -- Versioning
