-- Create a validation trigger that checks against leave_types table
CREATE OR REPLACE FUNCTION grxbooks.validate_leave_type_exists()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path TO 'public'
AS $func$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM grxbooks.leave_types
    WHERE key = NEW.leave_type AND is_active = true
  ) THEN
    RAISE EXCEPTION 'Invalid leave type: %. It must be an active leave type.', NEW.leave_type;
  END IF;
  RETURN NEW;
END;
$func$;

