DROP TRIGGER IF EXISTS trg_validate_leave_type_balance ON grxbooks.leave_balances;
CREATE TRIGGER trg_validate_leave_type_balance
  BEFORE INSERT OR UPDATE ON grxbooks.leave_balances
  FOR EACH ROW
  EXECUTE FUNCTION grxbooks.validate_leave_type_exists();


